INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 21, 'teens', 1, 'What lie did David tell Ahimelech to explain why he was traveling alone without an escort?', 'That the king had sent him on a secret urgent mission and his men would meet him later', 'That he was a pilgrim traveling to worship at a distant sanctuary', 'That he was fleeing enemies and had no time to gather servants', 'That he had been dismissed from the king''s court and was seeking a new lord', 'a', '1 Samuel 21:2 — "And David said unto Ahimelech the priest, The king hath commanded me a business, and hath said unto me, Let no man know any thing of the business whereabout I send thee."'),
('1 Samuel', 21, 'teens', 2, 'What condition did Ahimelech place on giving David the shewbread?', 'That David and his men had kept themselves from women', 'That David promised to bring a guilt offering afterward', 'That David swear an oath of loyalty to the priesthood', 'That David take only half of what was available', 'a', '1 Samuel 21:4-5 — "the priest answered David, and said, There is no common bread under mine hand, but there is hallowed bread; if the young men have kept themselves at least from women...And David answered the priest, and said unto him, Of a truth women have been kept from us about these three days."'),
('1 Samuel', 21, 'teens', 3, 'Who was present at Nob that day and later reported David''s visit to Saul?', 'Doeg the Edomite, Saul''s chief herdsman', 'Abner the captain of the host', 'Ish-bosheth, Saul''s son', 'Cush the Benjamite', 'a', '1 Samuel 21:7 — "Now a certain man of the servants of Saul was there that day, detained before the LORD; and his name was Doeg, an Edomite, the chiefest of the herdmen that belonged to Saul."'),
('1 Samuel', 21, 'teens', 4, 'Whose sword did David receive from Ahimelech at Nob, and where had it been kept?', 'Goliath''s sword, wrapped in a cloth behind the ephod', 'Jonathan''s sword, stored in the ark room', 'Samuel''s ceremonial sword, kept in the inner sanctuary', 'Saul''s spare sword, left there during a worship visit', 'a', '1 Samuel 21:9 — "And the priest said, The sword of Goliath the Philistine, whom thou slewest in the valley of Elah, behold, it is here wrapped in a cloth behind the ephod."'),
('1 Samuel', 21, 'teens', 5, 'How did David escape being harmed by Achish king of Gath?', 'He feigned madness — scrabbling on the doors and letting his spittle fall on his beard — so Achish dismissed him as a lunatic', 'He appealed to a treaty between Israel and Gath', 'He bribed Achish''s servants to help him escape at night', 'He challenged a Philistine champion to combat and was released as a champion himself', 'a', '1 Samuel 21:13 — "And he changed his behaviour before them, and feigned himself mad in their hands, and scrabbled on the doors of the gate, and let his spittle fall down upon his beard."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 21, 'adults', 1, 'What does Ahimelech''s fear at David''s solitary arrival (21:1) suggest about the political atmosphere in Saul''s kingdom?', 'The priest recognized that an unescorted appearance by the king''s son-in-law was politically abnormal and potentially dangerous, showing that court paranoia had spread even to the sanctuaries', 'Ahimelech feared David because of an old personal feud between them', 'The priest was afraid because David arrived armed with Goliath''s sword', 'Ahimelech feared David was bringing news of a Philistine invasion', 'a', '1 Samuel 21:1 — "and Ahimelech was afraid at the meeting of David, and said unto him, Why art thou alone, and no man with thee?" The question reveals that a lone royal courier was an anomaly that signaled danger.'),
('1 Samuel', 21, 'adults', 2, 'How did Jesus use the incident of David eating the shewbread (Matt. 12:3-4) to refute the Pharisees'' accusation about the Sabbath?', 'Jesus argued that David''s pressing need overrode the ceremonial law''s restriction on the shewbread, establishing the principle that mercy and human need take precedence over ritual prohibition when the two conflict', 'Jesus used the passage to prove that priests could authorize any act of worship', 'Jesus cited it only as a historical parallel with no theological argument about the law''s purpose', 'Jesus used it to prove David was greater than Moses and therefore exempt from all law', 'a', 'Matthew 12:3-4 — "Have ye not read what David did, when he was an hungred...How he entered into the house of God, and did eat the shewbread, which was not lawful for him to eat." The argument turns on the priority of mercy over sacrifice (Matt. 12:7, citing Hosea 6:6).'),
('1 Samuel', 21, 'adults', 3, 'What is the theological tension in David''s deception of Ahimelech, given that David is the text''s protagonist and future king after God''s own heart?', 'The narrative presents David as a fully human figure whose acts of deception — like the patriarchs before him — are reported without endorsement; the consequences (Nob''s massacre, 1 Sam. 22) show that deception, even by the elect, produces real and terrible downstream harm', 'The narrative endorses David''s deception as justified by Saul''s tyranny', 'The text condemns David explicitly for lying to Ahimelech in this chapter', 'There is no tension because deception for self-preservation was permitted under Mosaic law', 'a', '1 Samuel 22:22 — "And David said unto Abiathar, I knew it that day, when Doeg the Edomite was there...I have occasioned the death of all the persons of thy father''s house." David himself later admits that his actions at Nob contributed to the massacre.'),
('1 Samuel', 21, 'adults', 4, 'What does the presence of Doeg "detained before the LORD" at Nob imply about the setting, and how does it function in the narrative?', 'Doeg was likely fulfilling a religious vow or purification requirement at the sanctuary — the detail of sacred space makes his later treachery (reporting to Saul and slaughtering the priests) all the more sinister as a violation of both sanctuary law and loyalty', 'Doeg was a priest in training at Nob and used his inside knowledge to help Saul', 'He was detained as a prisoner and had no special access to sanctuary events', 'The phrase "detained before the LORD" means he was sick and seeking healing there', 'a', '1 Samuel 21:7 — "detained before the LORD." The Hebrew (_atzur_) is the same word used of Nazirite vows and ritual separation, implying a religious obligation — making Doeg''s presence in a holy place and his subsequent murder of 85 priests a profound desecration.'),
('1 Samuel', 21, 'adults', 5, 'What is the significance of David receiving Goliath''s sword specifically at this moment in the narrative?', 'Goliath''s sword is a symbol of David''s greatest public triumph; its reappearance as he flees in fear and disguise creates an ironic contrast — the man who was once Israel''s champion now hides in an enemy city, marking the depth of his humiliation before his eventual exaltation', 'The sword was simply the only weapon available and the detail carries no narrative significance', 'The sword represents David''s intention to use Philistine weapons to retake the throne immediately', 'Goliath''s sword was kept at Nob as a trophy of Israel''s victory over all Philistines', 'a', '1 Samuel 21:9 — "There is none like that; give it me." David''s words echo the sword''s incomparable association with his greatest victory, while his current situation — a fugitive in Gath, Goliath''s own city — is the sharpest possible irony.'),
('1 Samuel', 21, 'adults', 6, 'How does David''s flight to Gath — Goliath''s home city — reflect the desperate pragmatism of his situation, and what risk did it entail?', 'David calculated that Saul''s reach would not extend into Philistine territory, but in doing so he entered the city of his most famous enemy and was immediately recognized by Achish''s servants as "the king of the land" — so the plan was immediately life-threatening', 'Going to Gath was safe because the Philistines respected David as a great warrior', 'David went to Gath to negotiate a military alliance against Saul', 'The servants of Achish did not recognize David and the risk was minimal', 'a', '1 Samuel 21:11 — "And the servants of Achish said unto him, Is not this David the king of the land? did they not sing one to another of him in dances, saying, Saul hath slain his thousands, and David his ten thousands?"'),
('1 Samuel', 21, 'adults', 7, 'Psalm 34 is attributed to the episode at Gath in its superscription. What theological claim does the psalm make that stands in ironic contrast to David''s apparent helplessness?', 'Psalm 34 proclaims "I sought the LORD, and he heard me, and delivered me from all my fears" — David''s trust in divine deliverance is expressed in the very psalm that commemorates his most humiliating moment, modeling faith that transcends circumstances', 'Psalm 34 is a lament that God had abandoned David in Gath', 'Psalm 34 celebrates David''s own cleverness in feigning madness as the means of salvation', 'The psalm''s superscription is a later addition with no connection to 1 Samuel 21', 'a', 'Psalm 34:4 — "I sought the LORD, and he heard me, and delivered me from all my fears." The superscription reads "A Psalm of David, when he changed his behaviour before Abimelech" — Abimelech being likely a dynastic title for Achish.'),
('1 Samuel', 21, 'adults', 8, 'What does the detail that David "changed his behaviour" (21:13) — literally "changed his discretion/taste" (Hebrew: _ta''am_) — suggest about the nature of David''s act?', 'The Hebrew _ta''am_ (discretion, judgment) implies David deliberately suspended his normal royal dignity and shrewd judgment, performing gross irrationality — the act was a calculated suspension of identity, theologically resonant with the later theme of God''s wisdom appearing as foolishness', 'The word simply means David became afraid and acted instinctively', 'The Hebrew term indicates David received a prophetic spirit that altered his behavior involuntarily', 'The act was a sin that David later repented of in Psalm 34', 'a', '1 Samuel 21:13 — "And he changed his behaviour before them, and feigned himself mad in their hands." The root _ta''am_ appears in Proverbs for wisdom/discretion, making its deliberate "change" here a rich inversion — madness as strategy.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 22, 'teens', 1, 'What kind of people gathered to David at the cave of Adullam?', 'Everyone in distress, in debt, or discontented — about four hundred men', 'Trained soldiers from Judah seeking a new commander', 'Priests who had fled from Saul''s court', 'Philistine mercenaries who preferred David''s leadership', 'a', '1 Samuel 22:2 — "And every one that was in distress, and every one that was in debt, and every one that was discontented, gathered themselves unto him; and he became a captain over them."'),
('1 Samuel', 22, 'teens', 2, 'Where did David take his father and mother for their safety while he was a fugitive?', 'To the king of Moab in Mizpeh', 'To the cave of Adullam with his men', 'To the city of Hebron in Judah', 'To the prophet Gad in Ramah', 'a', '1 Samuel 22:3-4 — "And David went thence to Mizpeh of Moab: and he said unto the king of Moab, Let my father and my mother, I pray thee, come forth, and be with you...And he brought them before the king of Moab: and they dwelt with him all the while that David was in the hold."'),
('1 Samuel', 22, 'teens', 3, 'What did the prophet Gad tell David to do after he had placed his parents in Moab?', 'To leave the hold and go into the land of Judah', 'To go to the wilderness of Sinai and fast for forty days', 'To return to Nob and seek guidance from the priests', 'To gather his men and attack Saul''s forward camp', 'a', '1 Samuel 22:5 — "And the prophet Gad said unto David, Abide not in the hold; depart, and get thee into the land of Judah. Then David departed, and came into the forest of Hareth."'),
('1 Samuel', 22, 'teens', 4, 'How did Saul find out that Ahimelech had helped David, and what accusation did Saul make against his own servants?', 'Doeg the Edomite reported it; Saul accused his servants of conspiring with David against him', 'A spy sent to Nob reported it; Saul accused the priests of rebellion', 'Jonathan confessed; Saul accused his son of treason', 'Abner discovered it on patrol; Saul accused his army of disloyalty', 'a', '1 Samuel 22:9-10,13 — "Then answered Doeg the Edomite...and said, I saw the son of Jesse coming to Nob...And Saul said unto him, Why have ye conspired against me, thou and the son of Jesse?"'),
('1 Samuel', 22, 'teens', 5, 'One son of the priest Ahimelech escaped the massacre at Nob and came to David. Who was he?', 'Abiathar', 'Zadok', 'Phinehas', 'Ichabod', 'a', '1 Samuel 22:20 — "And one of the sons of Ahimelech the son of Ahitub, named Abiathar, escaped, and fled after David."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 22, 'adults', 1, 'How does the description of David''s followers in 22:2 — distressed, in debt, discontented — ironically prefigure the nature of the messianic community?', 'The marginal and broken people who rally to the rejected anointed one form a pattern repeated in the ministry of Jesus, who gathered tax collectors, sinners, and the poor — the Adullam community is a type of the kingdom gathered around the true king in his humiliation', 'The description is neutral social history with no theological resonance', 'The passage argues that David''s followers were morally deficient and thus a liability', 'The text implies David was a social revolutionary deliberately targeting the underclass', 'a', '1 Samuel 22:2 — "every one that was in distress, and every one that was in debt, and every one that was discontented, gathered themselves unto him." Luke 4:18 echoes this gathering-of-the-broken pattern in Jesus'' inaugural sermon at Nazareth.'),
('1 Samuel', 22, 'adults', 2, 'What is the significance of David''s Moabite connection — placing his parents with the king of Moab — in light of his genealogy?', 'David''s great-grandmother Ruth was a Moabitess (Ruth 4:17-22), so his appeal to Moab was a family connection; this detail ties the books of Ruth and 1 Samuel together and grounds David''s international dimensions in covenant history', 'David''s Moabite connection was purely pragmatic with no genealogical significance', 'The text implies Moab was the only neutral territory available to David', 'David''s connection to Moab came from his mother''s side unrelated to Ruth', 'a', '1 Samuel 22:3 — "Let my father and my mother, I pray thee, come forth, and be with you." Ruth 4:17 — "they called his name Obed: he is the father of Jesse." David''s roots in Ruth''s Moab make this diplomatic appeal a family reunion.'),
('1 Samuel', 22, 'adults', 3, 'Saul''s speech in 22:6-8 reveals what about his psychological and political deterioration?', 'Saul frames the entire situation as a conspiracy by his Benjamite tribesmen in favor of Jesse''s son — his accusation of universal betrayal, his appeal to tribal loyalty, and his claim that no one tells him anything reveal paranoia and isolation that has dissolved his capacity for just rule', 'Saul''s speech is a measured political assessment of a genuine threat to his throne', 'Saul was correct in every accusation he made in this speech', 'The speech shows Saul had regained his composure and was handling the crisis wisely', 'a', '1 Samuel 22:8 — "there is none of you that is sorry for me, or sheweth unto me that my son hath made a league with the son of Jesse, and there is none of you that sheweth unto me that my son hath stirred up my servant against me, to lie in wait, as at this day."'),
('1 Samuel', 22, 'adults', 4, 'How does Ahimelech''s defense (22:14-15) contrast with Saul''s accusation, and what does his reply reveal about his knowledge?', 'Ahimelech argues from David''s official standing — king''s son-in-law, captain of the guard, honored in the house — not knowing about the breach between them; his ignorance of political realities shows how Saul''s paranoia had become a private secret rather than public royal policy', 'Ahimelech knew about the rift between David and Saul but helped David anyway out of loyalty', 'Ahimelech''s defense was a calculated lie designed to protect himself', 'Ahimelech knew nothing about David''s anointing and defended him purely on past behavior', 'a', '1 Samuel 22:14-15 — "And Ahimelech answered the king, and said, And who is so faithful among all thy servants as David...Did I then begin to enquire of God for him? be it far from me: let not the king impute any thing unto his servant." Ahimelech''s questions show genuine bewilderment.'),
('1 Samuel', 22, 'adults', 5, 'Why did Saul''s servants refuse to carry out the king''s order to kill the priests, and what does their refusal signify?', 'The servants would not "fall upon the priests of the LORD" — the combination of sacral immunity and the evident injustice of the command produced a rare instance of corporate disobedience, showing that even Saul''s own men recognized a limit to royal authority over the sacred', 'Saul''s servants refused because they were personally loyal to Ahimelech''s family', 'The servants refused because they feared David''s men would retaliate', 'The servants obeyed but only killed a portion of the priests as a compromise', 'a', '1 Samuel 22:17 — "But the servants of the king would not put forth their hand to fall upon the priests of the LORD." The refusal — unique in Saul''s court — highlights the extremity of the command and Doeg''s willingness to violate what Saul''s own men would not.'),
('1 Samuel', 22, 'adults', 6, 'How does the massacre at Nob fulfill the prophecy spoken against the house of Eli in 1 Samuel 2:27-36?', 'The man of God prophesied that Eli''s priestly line would be cut off and there would be no old man in his house — the slaughter of 85 priests at Nob, all descendants of Eli through Ithamar, is the violent fulfillment of that announced judgment', 'The Nob massacre was unrelated to the prophecy against Eli''s house', 'The prophecy against Eli was fulfilled only when Solomon removed Abiathar in 1 Kings 2', 'Ahimelech was not a descendant of Eli and therefore the massacre did not fulfill the earlier prophecy', 'a', '1 Samuel 2:33-34 — "the man of thine, whom I shall not cut off from mine altar...And this shall be a sign unto thee, that shall come upon thy two sons...they shall die both of them in one day." 1 Samuel 22:18 — eighty-five priests in linen ephods slain in one day.'),
('1 Samuel', 22, 'adults', 7, 'What does David''s acceptance of moral responsibility in 22:22 ("I have occasioned the death of all the persons of thy father''s house") reveal about his character at this stage of his life?', 'David''s self-indictment — rare among ancient protagonists — shows a capacity for moral accountability that distinguishes him from Saul, who consistently deflects blame; this willingness to own consequences of his deception is a mark of the "man after God''s own heart"', 'David''s statement was merely a polite expression of condolence without genuine self-blame', 'David''s admission proves he was unfit to be king because he had made a serious error', 'David blamed himself only to keep Abiathar loyal by making him feel valued', 'a', '1 Samuel 22:22 — "And David said unto Abiathar, I knew it that day, when Doeg the Edomite was there, that he would surely tell Saul: I have occasioned the death of all the persons of thy father''s house." Compare with Saul''s pattern of blame-shifting in 1 Sam. 15:15.'),
('1 Samuel', 22, 'adults', 8, 'Psalm 52 is attributed to the occasion of Doeg''s treachery. How does its portrait of the "mighty man" who "boastest in mischief" apply to Doeg, and what hope does the psalm offer?', 'Psalm 52 describes a man whose tongue works destruction, who trusts in the abundance of riches rather than in God — Doeg, whose one report caused 85 deaths, fits precisely; the psalm promises the wicked will be uprooted while the righteous will flourish like a green olive tree in the house of God', 'Psalm 52 is addressed to Saul, not Doeg, and describes royal misuse of power', 'The psalm describes David''s own failures and is a psalm of repentance for the Nob events', 'The psalm''s attribution to this event is a later tradition with no exegetical significance', 'a', 'Psalm 52:1,5,8 — "Why boastest thou thyself in mischief, O mighty man?...God shall likewise destroy thee for ever...But I am like a green olive tree in the house of God: I trust in the mercy of God for ever and ever."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 23, 'teens', 1, 'How did David determine whether to go to Keilah''s aid, and what tool did he use?', 'He inquired of the LORD twice through the ephod, asking first whether to go and then whether Keilah''s men would betray him', 'He consulted the prophet Gad who gave him a direct word', 'He sent spies to assess the Philistine strength and made a tactical decision', 'He used the Urim and Thummim by asking the high priest Eli', 'a', '1 Samuel 23:2,4 — "Therefore David enquired of the LORD, saying, Shall I go and smite these Philistines?...And David enquired of the LORD yet again. And the LORD answered him and said, Arise, go down to Keilah."'),
('1 Samuel', 23, 'teens', 2, 'When Saul heard David was in Keilah, what did Saul believe and what did God reveal would actually happen?', 'Saul believed God had delivered David into his hand because Keilah was a walled city; but God revealed that the men of Keilah would deliver David to Saul, so David fled', 'Saul believed David had fortified Keilah; God revealed David had already left', 'Saul believed Jonathan had warned David; God revealed the Ziphites would help Saul', 'Saul believed the Philistines were sheltering David; God revealed they had expelled him', 'a', '1 Samuel 23:7,11-12 — "And Saul said, God hath delivered him into mine hand...And the LORD said, They will deliver thee up...Then said David, Will the men of Keilah deliver me and my men into the hand of Saul? And the LORD said, They will deliver thee up."'),
('1 Samuel', 23, 'teens', 3, 'After David left Keilah, how many men were with him?', 'About six hundred men', 'About four hundred men', 'About one thousand men', 'About two hundred men', 'a', '1 Samuel 23:13 — "Then David and his men, which were about six hundred, arose and departed out of Keilah, and went whithersoever they could go."'),
('1 Samuel', 23, 'teens', 4, 'What covenant did Jonathan and David renew when they met secretly in the wood of Ziph?', 'They made a covenant before the LORD that Jonathan would be next to David when David became king', 'They renewed their oath that neither would ever make peace with Saul', 'They agreed that Jonathan would betray Saul''s battle plans to David', 'They pledged that David would spare Jonathan''s entire tribe in the coming war', 'a', '1 Samuel 23:18 — "And they two made a covenant before the LORD: and David abode in the wood, and Jonathan went to his house."'),
('1 Samuel', 23, 'teens', 5, 'How was David dramatically saved from Saul''s encirclement in the wilderness of Maon?', 'A messenger came to Saul saying the Philistines had invaded, forcing Saul to break off the pursuit', 'Jonathan arrived and diverted Saul''s attention long enough for David to escape', 'A sudden rainstorm made the terrain impassable for Saul''s army', 'David''s men ambushed Saul''s rear guard, forcing a retreat', 'a', '1 Samuel 23:27-28 — "But there came a messenger unto Saul, saying, Haste thee, and come; for the Philistines have invaded the land. Wherefore Saul returned from pursuing after David, and went against the Philistines."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 23, 'adults', 1, 'David inquires of the LORD twice before going to Keilah (23:2,4) — once for permission and once to address his men''s fear. What does this double inquiry reveal about his leadership model versus Saul''s?', 'David''s habitual consultation of God before action — seeking divine permission, then divine reassurance — contrasts sharply with Saul''s pattern of acting first and consulting God only to ratify decisions already made (1 Sam. 13-14); David models theocratic leadership rather than autonomous kingship', 'The double inquiry shows David lacked confidence and needed constant reassurance', 'Both David and Saul consulted God with equal frequency at this point in the narrative', 'David''s second inquiry was unnecessary and shows a deficiency of faith', 'a', '1 Samuel 23:4 — "And David enquired of the LORD yet again." The pattern of seeking God''s guidance at every decision point — including 23:9-12, three questions through the ephod — establishes David as a king who walks by divine word, not by sight.'),
('1 Samuel', 23, 'adults', 2, 'What does the fact that the men of Keilah — whom David had just rescued — would have betrayed him (23:12) suggest about the nature of David''s sufferings as a type of the Messiah?', 'David saves a city at personal risk and that city would repay him with betrayal; this prefigures the pattern of the true King who comes to save his people and is rejected by those he delivered — the rescued becoming accusers is a recurring biblical pattern in both Testaments', 'The Keilah episode is purely political with no typological significance', 'The betrayal proves David should not have saved Keilah in the first place', 'The men of Keilah were Canaanites and their betrayal reflects pagan unreliability rather than a theological pattern', 'a', '1 Samuel 23:12 — "Then said David, Will the men of Keilah deliver me and my men into the hand of Saul? And the LORD said, They will deliver thee up." John 1:11 — "He came unto his own, and his own received him not."'),
('1 Samuel', 23, 'adults', 3, 'Jonathan''s final visit to David (23:16-18) is described as him "strengthening his hand in God." What is the theological content of that act?', 'Jonathan''s strengthening was not merely emotional support but theological reorientation — he reminded David of God''s promises, acknowledged David''s future kingship, and located his own role within God''s plan; this is pastoral theology enacted in a fugitive camp', 'Jonathan''s visit was a military strategy session disguised as encouragement', '"Strengthening his hand in God" is an idiom for sharing a meal, with no theological content', 'Jonathan''s visit was primarily to receive intelligence about Saul''s movements from David', 'a', '1 Samuel 23:16-17 — "And Jonathan Saul''s son arose, and went to David into the wood, and strengthened his hand in God. And he said unto him...thou shalt be king over Israel, and I shall be next unto thee; and that also Saul my father knoweth."'),
('1 Samuel', 23, 'adults', 4, 'This is the last recorded meeting of David and Jonathan. How does the narrative handle the weight of this farewell?', 'The text says "they two made a covenant before the LORD" and Jonathan "went to his house" — the brevity is itself eloquent; the covenant seals their relationship with divine witness before Jonathan exits the story, making the unspoken finality more powerful than explicit lament', 'The text includes a long farewell speech by Jonathan lamenting their separation', 'The text reports that David wept extensively at the parting', 'The narrative presents the meeting as a routine military conference with no emotional register', 'a', '1 Samuel 23:18 — "And they two made a covenant before the LORD: and David abode in the wood, and Jonathan went to his house." Jonathan will appear only in battle reports (31:2) until his death — this quiet exit is his canonical farewell.'),
('1 Samuel', 23, 'adults', 5, 'The Ziphites betray David twice in 1 Samuel (23:19 and 26:1). What does their repeated treachery reveal about the limits of tribal loyalty in Saul''s Israel?', 'The Ziphites were fellow Judahites — David''s own tribe — yet betrayed him to a Benjamite king; this shows that Saul''s authority had co-opted even David''s own tribal constituency, and that tribal solidarity cannot be assumed as a safe haven for the anointed', 'The Ziphites were non-Israelites who had no obligation of tribal loyalty to David', 'The Ziphites'' betrayal shows they feared the Philistines more than they feared Saul', 'The double betrayal is a textual error — the two incidents are the same event reported twice', 'a', '1 Samuel 23:19 — "Then came up the Ziphites to Saul to Gibeah, saying, Doth not David hide himself with us?" Psalm 54 is attributed to this betrayal: "for strangers are risen up against me" — ironically calling his own tribesmen "strangers."'),
('1 Samuel', 23, 'adults', 6, 'What does the place name "Sela-hammahlekoth" (Rock of Escape, 23:28) contribute to the theology of providence in this chapter?', 'The naming of the rock commemorates God''s providential rescue through a historically contingent event — a Philistine raid — at the precise moment of David''s capture; the place-name becomes a permanent testimony inscribed in geography that God''s timing is sovereign even through enemy military action', 'The place name is merely a topographical description with no theological significance', 'The rock was named by Saul to commemorate his near-capture of David', 'The name records David''s military escape tactic rather than divine deliverance', 'a', '1 Samuel 23:28 — "Wherefore Saul returned from pursuing after David, and went against the Philistines: therefore they called that place Sela-hammahlekoth." The place-name encodes a theology of providential rescue — enemies became instruments of salvation.'),
('1 Samuel', 23, 'adults', 7, 'Psalm 54 is attributed to the Ziphite betrayal in its superscription. How does its opening petition ("Save me, O God, by thy name") relate to the concept of divine name-theology in the Old Testament?', 'The appeal to God''s "name" invokes the totality of God''s revealed character and covenant commitments — to be saved "by thy name" is to be saved by all that God has disclosed himself to be (faithful, just, powerful); it is a more theologically dense request than simply "save me"', 'The appeal to God''s name is merely a conventional opening formula with no specific theological content', 'The appeal to God''s name in Psalm 54 is specifically a request for a theophany like Sinai', 'The petition invokes God''s personal name (YHWH) as a magical formula for protection', 'a', 'Psalm 54:1-2 — "Save me, O God, by thy name, and judge me by thy strength. Hear my prayer, O God; give ear to the words of my mouth." Proverbs 18:10 — "The name of the LORD is a strong tower: the righteous runneth into it, and is safe."'),
('1 Samuel', 23, 'adults', 8, 'How does chapter 23 as a whole demonstrate the tension between divine sovereignty and human contingency in guiding David''s path?', 'Chapter 23 shows God actively guiding David through means as varied as direct oracle (vv.2,4,11-12), prophetic counsel (v.5, Gad implied), Jonathan''s ministry (v.16), and Philistine invasion (v.27) — the chapter refuses a single mode of divine guidance, showing God weaving together revelation, community, and historical events into a seamless providential rescue', 'Chapter 23 shows God acting only through direct prophecy and never through secondary causes', 'The chapter shows primarily human ingenuity saving David, with divine guidance as a minor element', 'Providence in chapter 23 operates only through Abiathar''s ephod as the exclusive means', 'a', '1 Samuel 23:14 — "And Saul sought him every day, but God delivered him not into his hand." This summary statement over the entire chapter identifies the outcome as divine even while the means are various and fully human.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 24, 'teens', 1, 'After Saul left the cave and David confronted him, what evidence did David present to prove he could have killed Saul but chose not to?', 'He held up the piece of Saul''s robe, showing his restraint in only cutting the skirt rather than taking Saul''s life', 'He displayed Saul''s sword which his men had taken while Saul slept', 'He showed Saul a written message he had left inside the cave warning Saul of his danger', 'He produced witnesses from his men who confirmed they had held David back from killing Saul', 'a', '1 Samuel 24:11 — "Moreover, my father, see, yea, see the skirt of thy robe in my hand: for in that I cut off the skirt of thy robe, and killed thee not, know thou and see that there is neither evil nor transgression in mine hand."'),
('1 Samuel', 24, 'teens', 2, 'What proverb did David quote to explain how a wicked king need not be feared?', '"Wickedness proceedeth from the wicked: but mine hand shall not be against thee"', '"As saith the proverb of the ancients, Out of the wicked cometh forth wickedness"', '"A man reaps what he sows, and the wicked shall fall by his own sword"', '"Evil pursues sinners, but the LORD protects the righteous"', 'a', '1 Samuel 24:13 — "As saith the proverb of the ancients, Wickedness proceedeth from the wicked: but mine hand shall not be against thee."'),
('1 Samuel', 24, 'teens', 3, 'To what animal did David compare himself before Saul to emphasize how little a threat he posed?', 'A dead dog and a flea', 'A lamb and a sparrow', 'A locust and a grasshopper', 'A wounded bird and a moth', 'a', '1 Samuel 24:14 — "After whom is the king of Israel come out? after whom dost thou pursue? after a dead dog, after a flea?"'),
('1 Samuel', 24, 'teens', 4, 'What did David appeal to God to do between him and Saul?', 'To judge between them and plead David''s cause and deliver him from Saul''s hand', 'To strike Saul dead before the day was over', 'To give David the same number of soldiers Saul possessed', 'To reveal through prophecy who was righteous in the dispute', 'a', '1 Samuel 24:15 — "The LORD therefore be judge, and judge between me and thee, and see, and plead my cause, and deliver me out of thine hand."'),
('1 Samuel', 24, 'teens', 5, 'How did Saul respond to David''s speech, and what did he ask David to swear?', 'Saul wept, called David more righteous than himself, acknowledged David would be king, and asked David to swear not to cut off his seed', 'Saul praised David''s restraint but refused to stop pursuing him', 'Saul repented of his hatred and invited David back to the palace', 'Saul agreed to a permanent truce and exchanged hostages as guarantee', 'a', '1 Samuel 24:16-17,20-21 — "And it came to pass, when David had made an end of speaking these words unto Saul, that Saul said, Is this thy voice, my son David? And Saul lifted up his voice, and wept...Thou art more righteous than I...And now, behold, I know well that thou shalt surely be king...Swear now therefore unto me by the LORD, that thou wilt not cut off my seed after me."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 24, 'adults', 1, 'David''s men interpret the cave encounter as God delivering Saul into David''s hand (24:4). How does David''s theological rebuttal reframe the meaning of providential opportunity?', 'David argues that a providential opportunity is not automatically a divine command — God delivering an enemy into one''s vicinity does not mean God commands one to kill; this distinguishes between divine permission and divine directive, a crucial distinction in biblical ethics', 'David agreed the opportunity was God''s command but chose disobedience out of personal affection for Saul', 'David''s rebuttal was based on practical fear of political consequences, not theological conviction', 'David believed he misunderstood the oracle and that God had not actually delivered Saul to him', 'a', '1 Samuel 24:6 — "The LORD forbid that I should do this thing unto my master, the LORD''s anointed, to stretch forth mine hand against him." David''s conscience is governed by principle ("the LORD''s anointed"), not by circumstantial opportunity.'),
('1 Samuel', 24, 'adults', 2, 'What does the cutting of the robe''s skirt specifically signify in the cultural context of the ancient Near East, and what is its irony here?', 'In ANE diplomacy, seizing the hem/skirt of a garment symbolized claiming authority or suzerainty over its owner — David''s act, even in restraint, is symbolically a claim of dominion over Saul, and his subsequent guilt shows he understood the symbolic transgression even while sparing the man', 'The robe-cutting was a purely practical act to prove David''s proximity with no symbolic dimension', 'The hem of a garment had no symbolic significance in Israel or the broader ANE', 'David cut the robe purely to embarrass Saul publicly rather than for any symbolic reason', 'a', '1 Samuel 24:5 — "David''s heart smote him, because he had cut off Saul''s skirt." The Hebrew word for "skirt/hem" (_kanaph_) also means "wing/authority." Ezekiel 16:8 uses the same word for God spreading his "skirt" over Israel in a covenant act.'),
('1 Samuel', 24, 'adults', 3, 'How does David''s speech in 24:9-15 deploy legal vocabulary, and what does this reveal about his conception of justice?', 'David uses the language of lawsuit — "judge between me and thee," "plead my cause," "deliver me" — framing the conflict not as a power struggle but as a legal case before the divine judge; this covenantal-legal framework is how David consistently processes injustice throughout the psalms', 'David''s speech is purely emotional rhetoric with no legal or covenantal framework', 'David appeals to the law of Moses by citing specific statutes Saul had violated', 'The legal language is a diplomatic formula with no indication of David''s personal theology', 'a', '1 Samuel 24:15 — "The LORD therefore be judge, and judge between me and thee, and see, and plead my cause, and deliver me out of thine hand." This is the language of the _rib_ (covenant lawsuit), which David employs extensively in Psalms 7, 35, and 109.'),
('1 Samuel', 24, 'adults', 4, 'Saul''s emotional response — weeping and confessing David''s righteousness (24:16-17) — followed by his resumption of pursuit (26:2) presents what psychological and theological problem?', 'Saul demonstrates emotional remorse without genuine repentance — his tears acknowledge truth but produce no lasting behavioral change; this is the sorrow of the world that produces death (2 Cor. 7:10) rather than godly sorrow that leads to life, a pattern visible earlier in his post-Amalek confession (15:24)', 'Saul''s tears were genuine repentance but David''s subsequent behavior made reconciliation impossible', 'The text implies Saul''s remorse was complete and his later pursuit was due to demonic compulsion outside his control', 'Saul''s confession was entirely tactical — designed to lure David out of hiding', 'a', '1 Samuel 24:17 — "Thou art more righteous than I." 1 Samuel 26:2 — "Then Saul arose, and went down to the wilderness of Ziph...to seek David." True repentance changes direction; Saul''s emotions change but his trajectory does not.'),
('1 Samuel', 24, 'adults', 5, 'What does the structural parallel between chapters 24 and 26 — two cave/camp encounters where David spares Saul — achieve narratively?', 'The doubling is a deliberate narrative device that confirms David''s restraint as a settled principle rather than a one-time decision — the second incident proves the first was not circumstantial; together they establish "refusing to harm the LORD''s anointed" as a defining characteristic of David''s kingship', 'The two incidents are likely the same event reported from different sources with no intentional parallelism', 'The doubling shows David needed two divine confirmations before he could be certain of his calling', 'The parallel structure argues David was wrong the second time and should have acted', 'a', '1 Samuel 26:11 — "The LORD forbid that I should stretch forth mine hand against the LORD''s anointed." The verbatim echo of 24:6 confirms intentional narrative doubling — David''s principle is tested twice and holds.'),
('1 Samuel', 24, 'adults', 6, 'David''s appeal to the "LORD judge between me and thee" (24:15) contrasts with his men''s urging him to act himself. What does this contrast teach about the biblical concept of vengeance?', 'David refuses to become God''s executioner on his own authority — he defers vengeance to the divine judge, embodying the principle of Romans 12:19: "Vengeance is mine; I will repay, saith the Lord." This restraint is presented as the paradigmatic response to persecution throughout the wisdom and prophetic literature', 'David''s deferral of vengeance was a tactical delay rather than a theological commitment', 'The biblical text presents David''s restraint as admirable but not normative for ordinary Israelites', 'David''s men were correct and the text implicitly criticizes his failure to act', 'a', '1 Samuel 24:12 — "The LORD judge between me and thee, and the LORD avenge me of thee: but mine hand shall not be upon thee." Romans 12:19 — "Dearly beloved, avenge not yourselves...for it is written, Vengeance is mine; I will repay, saith the Lord."'),
('1 Samuel', 24, 'adults', 7, 'Saul''s acknowledgment that David will "surely be king" and that "the kingdom of Israel shall be established in thine hand" (24:20) is striking because it comes from his enemy. What is the theological function of this forced confession?', 'The involuntary confession of David''s future kingship by the reigning king who is trying to prevent it becomes a divine oath of sorts — God''s purposes are confirmed by the very mouth of opposition, echoing how Balaam blessed Israel rather than cursed it (Num. 23-24) and how Caiaphas prophesied unwittingly (John 11:51)', 'Saul''s confession was simply a political concession with no theological function', 'The confession represents Saul''s genuine conversion and full acceptance of God''s plan at this point', 'Saul was lying in order to secure David''s oath about his descendants', 'a', '1 Samuel 24:20 — "And now, behold, I know well that thou shalt surely be king, and that the kingdom of Israel shall be established in thine hand." Numbers 23:8 — "How shall I curse, whom God hath not cursed?" Even enemies become instruments of divine declaration.'),
('1 Samuel', 24, 'adults', 8, 'What is the significance of the location name "Engedi" (spring of the wild goat) in chapter 24, and how does the setting enhance the chapter''s themes?', 'Engedi was a wilderness oasis — a place of life in desolation where wild animals sheltered; the "strongholds of Engedi" (24:22) represent the hidden place where the fugitive king-in-waiting was preserved, and the rock hides and goat imagery align with the Psalms'' cave-refuge theology attributed to this period (Ps. 57, 142)', 'The setting at Engedi has no thematic significance and is merely a geographical note', 'Engedi was chosen because its terrain was militarily advantageous and the name carries no symbolic weight', 'The spring of Engedi was a sacred site where David went to worship, not to hide', 'a', '1 Samuel 24:1 — "David...dwelt in the strongholds of Engedi." Psalm 57 superscription — "when he fled from Saul in the cave." Song of Solomon 1:14 uses Engedi as a metaphor for beauty hidden in wilderness — the oasis-in-desert imagery recurs through the canon.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 25, 'teens', 1, 'What reasonable request did David''s young men make to Nabal at the sheepshearing feast, and on what basis did they make it?', 'They asked for provisions since David''s men had protected Nabal''s shepherds in the wilderness without any harm coming to them or their flocks', 'They asked Nabal to surrender his shepherds to serve in David''s army', 'They demanded a tribute of silver and gold befitting a future king', 'They asked only for permission to graze their own flocks on Nabal''s pastures', 'a', '1 Samuel 25:7-8 — "thy shepherds which were with us, we hurt them not, neither was there ought missing unto them...Give, I pray thee, whatsoever cometh to thine hand unto thy servants, and to thy son David."'),
('1 Samuel', 25, 'teens', 2, 'What insulting response did Nabal give, and what did his name literally mean in Hebrew?', 'Nabal refused contemptuously, asking "Who is David?" and his name in Hebrew meant "fool"', 'Nabal refused politely explaining he had nothing to spare, and his name meant "the generous"', 'Nabal threatened David with Saul''s army and his name meant "the proud"', 'Nabal ignored the messengers and sent them away and his name meant "the silent"', 'a', '1 Samuel 25:10-11,25 — "And Nabal answered David''s servants, and said, Who is David?...for as his name is, so is he; Nabal is his name, and folly is with him."'),
('1 Samuel', 25, 'teens', 3, 'What did Abigail bring to David on her donkeys to appease him before he could attack?', 'Two hundred loaves, two bottles of wine, five sheep, five measures of parched corn, a hundred clusters of raisins, and two hundred cakes of figs', 'Five lambs, three jars of oil, ten loaves, and a hundred measures of wine', 'Gold, silver, and fine linen along with bread and wine', 'A single sheep, ten loaves, and a letter of apology from Nabal', 'a', '1 Samuel 25:18 — "Then Abigail made haste, and took two hundred loaves, and two bottles of wine, and five sheep ready dressed, and five measures of parched corn, and an hundred clusters of raisins, and two hundred cakes of figs."'),
('1 Samuel', 25, 'teens', 4, 'What theological argument did Abigail use to persuade David not to avenge himself on Nabal?', 'She argued that shedding blood for personal revenge would be a grief and offence of heart to David when he became king, and that the LORD would avenge him', 'She reminded David of the Law of Moses which prohibited killing a man on his own land', 'She appealed to David''s mercy and offered herself as a sacrifice in Nabal''s place', 'She warned David that killing Nabal would turn all of Judah against him politically', 'a', '1 Samuel 25:31 — "That this shall be no grief unto thee, nor offence of heart unto my lord, either that thou hast shed blood causeless, or that my lord hath avenged himself: but when the LORD shall have dealt well with my lord, then remember thine handmaid."'),
('1 Samuel', 25, 'teens', 5, 'After Nabal died, what did David do, and what had Saul done with David''s first wife Michal?', 'David married Abigail and also took Ahinoam of Jezreel as wife, while Saul had given Michal to Phaltiel', 'David married Abigail and returned all her provisions as a wedding gift', 'David brought Abigail and Nabal''s entire household into his camp', 'David mourned Nabal''s death for seven days before sending for Abigail', 'a', '1 Samuel 25:42-44 — "And Abigail hasted, and arose...and she became his wife. David also took Ahinoam of Jezreel; and they were also both of them his wives. But Saul had given Michal his daughter, David''s wife, to Phaltiel."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 25, 'adults', 1, 'How does the placement of Samuel''s death notice (25:1) at the opening of a chapter about marriage and diplomacy function theologically?', 'Samuel''s death closes the era of prophetic oversight that governed Israel since his birth — his burial at Ramah marks the end of the old order, and David is now truly on his own under God''s direct guidance rather than prophetic intermediation, making his subsequent wisdom all the more dependent on divine providence', 'Samuel''s death is noted here only as a chronological marker with no structural significance', 'The notice marks Samuel''s death as divine judgment for his failure to anoint a better king', 'Samuel''s death is placed here to explain why David could not consult him about Nabal', 'a', '1 Samuel 25:1 — "And Samuel died; and all the Israelites were gathered together, and lamented him, and buried him in his house at Ramah. And David arose, and went down to the wilderness of Paran." The transition from national mourning to domestic episode is abrupt and deliberate.'),
('1 Samuel', 25, 'adults', 2, 'The name contrast "Nabal" (fool) and "Abigail" (my father is joy) functions in what way within the chapter''s wisdom-literature framework?', 'The names encode the chapter''s thesis — Nabal embodies Proverbs'' portrait of the fool who is wise in his own eyes and brings destruction on his house, while Abigail embodies the Proverbs 31 woman of wisdom whose action saves her household; the narrative is structured as a wisdom tale about two opposing responses to the same crisis', 'The name meanings are coincidental and the chapter is not structured along wisdom-literature lines', 'The name contrast is only relevant to the comedy of Nabal''s folly and carries no theological weight', 'Abigail''s name is symbolic but Nabal''s name simply reflects Israelite naming customs without evaluative intent', 'a', '1 Samuel 25:25 — "as his name is, so is he; Nabal is his name, and folly is with him." Proverbs 17:21 — "He that begetteth a fool doeth it to his sorrow." Abigail''s name (_avi-gil_) ironizes Nabal''s folly by contrast.'),
('1 Samuel', 25, 'adults', 3, 'Abigail''s speech in 25:24-31 contains prophetic elements. What does verse 29 specifically affirm about David''s standing?', 'Abigail declares that David''s soul shall be "bound in the bundle of life with the LORD" while his enemies'' souls will be "slung out, as out of the middle of a sling" — a life-death contrast using the sling imagery of David''s Goliath victory and affirming God''s covenantal protection of the anointed', 'Abigail''s prophecy was limited to promising David would not be harmed on this specific occasion', 'Verse 29 is merely flattery designed to calm David''s anger without theological content', 'Abigail predicted David would defeat all Philistines but said nothing about his covenant standing', 'a', '1 Samuel 25:29 — "the soul of my lord shall be bound in the bundle of life with the LORD thy God; and the souls of thine enemies, them shall he sling out, as out of the middle of a sling."'),
('1 Samuel', 25, 'adults', 4, 'David''s response "Blessed be thy advice...which hast kept me this day from coming to shed blood" (25:33) reveals what about the ethics of the situation?', 'David explicitly acknowledges that without Abigail''s intervention he would have committed a sin — taking revenge and shedding innocent blood — showing that God used a human instrument to prevent the LORD''s anointed from self-destructive vengeance', 'David''s response is polite social formula without admitting moral danger', 'David was in no real danger of sin since his oath to avenge was made in anger and would have been forgiven', 'David credits Abigail only with saving him from political embarrassment, not from moral failure', 'a', '1 Samuel 25:33-34 — "blessed be thou, which hast kept me this day from coming to shed blood, and from avenging myself with mine own hand. For in very deed...if thou hadst not hasted and come to meet me, surely there had not been left unto Nabal by the morning light any that pisseth against the wall."'),
('1 Samuel', 25, 'adults', 5, 'When Nabal''s "heart died within him, and he became as a stone" (25:37) ten days before his physical death, what literary and theological effect does this two-stage death create?', 'The sequence ensures the narrative connection between divine retribution and Nabal''s specific sin — the LORD''s smiting is the explicit cause, but the ten-day gap allows theological reflection: Nabal''s "heart of stone" is both a medical description and a moral verdict on his character', 'The ten-day delay is a naturalistic detail with no theological intentionality', 'Nabal''s stupor was caused by alcohol from the feast, not by divine judgment', 'The passage implies God struck Nabal immediately but his body simply took time to respond', 'a', '1 Samuel 25:37-38 — "his heart died within him, and he became as a stone. And it came to pass about ten days after, that the LORD smote Nabal, that he died." The stony heart is the moral opposite of Abigail''s wisdom and responsive spirit.'),
('1 Samuel', 25, 'adults', 6, 'How does David''s marriage to Abigail after Nabal''s death function within the larger narrative arc of his rise to kingship?', 'Abigail''s wisdom, household, wealth, and acknowledgment of David''s messianic destiny make her the fitting consort for the emerging king — the marriage consolidates resources and symbolically joins prophetic insight to royal potential, while Michal''s transfer to Phaltiel signals Saul''s formal disavowal of David as son-in-law', 'The marriage was purely personal with no political or theological significance', 'David''s marriage to Abigail was a moral error since he already had a wife in Michal', 'The marriage served only as a financial arrangement to fund David''s fugitive band', 'a', '1 Samuel 25:42-44 — "David also took Ahinoam of Jezreel...But Saul had given Michal his daughter, David''s wife, to Phaltiel." The three-way shift in marital arrangements reflects the realignment of alliances as the old kingdom collapses.'),
('1 Samuel', 25, 'adults', 7, 'Abigail''s intercessory role — placing herself between David''s wrath and Nabal''s household — echoes what other biblical patterns of mediatorial intercession?', 'Abigail functions as a human mediator who absorbs divine wrath on behalf of an unworthy party, echoing Moses'' intercession at Sinai (Ex. 32), Aaron''s standing between the living and the dead (Num. 16:48), and proleptically the Suffering Servant who stands between wrath and the guilty', 'Abigail''s role is unique in Scripture with no comparative pattern', 'The chapter models intercession only in the sense of diplomatic negotiation with no religious dimension', 'Abigail''s action parallels Rahab''s protection of the spies but has no intercessory theological content', 'a', '1 Samuel 25:24 — "Upon me, my lord, upon me let this iniquity be: and let thine handmaid, I pray thee, speak in thine audience." The formula of taking another''s guilt upon oneself is the language of substitutionary intercession found across the canon.'),
('1 Samuel', 25, 'adults', 8, 'How does chapter 25 as a whole function as a structural hinge in 1 Samuel''s narrative of David''s character development?', 'Chapter 25 tests David''s character in the domestic sphere — would he use his military power for personal vengeance when provoked? — and God''s answer comes through Abigail; having passed the Nabal test, David is ready for the even greater test of chapter 26 where he spares Saul again; the chapter shows divine education of the king through ordinary human situations', 'Chapter 25 is a narrative digression from the main David-Saul conflict with no structural function', 'The chapter exists primarily to explain how David gained his wealth before becoming king', 'Chapter 25 tests David''s military skill rather than his moral character', 'a', '1 Samuel 25:32-33 — "And David said to Abigail, Blessed be the LORD God of Israel, which sent thee this day to meet me." God sent Abigail — the providential framing means David is being instructed about patience and divine vengeance through a real-world parable.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 26, 'teens', 1, 'Who volunteered to go down with David into Saul''s camp at night?', 'Abishai the son of Zeruiah', 'Joab his brother', 'Abiathar the priest', 'Uriah the Hittite', 'a', '1 Samuel 26:6 — "Then answered David and said to Ahimelech the Hittite, and to Abishai the son of Zeruiah, brother to Joab, saying, Who will go down with me to Saul to the camp? And Abishai said, I will go down with thee."'),
('1 Samuel', 26, 'teens', 2, 'What did Abishai urge David to do when he saw Saul sleeping, and how did David refuse?', 'Abishai wanted to pin Saul to the ground with his own spear; David refused saying he would not smite the LORD''s anointed but would leave Saul to die by God''s hand or in battle', 'Abishai wanted to take Saul captive; David refused because it would start civil war', 'Abishai wanted to steal Saul''s royal seal; David refused because that would be theft', 'Abishai wanted to wake Saul and demand he surrender; David refused because of the noise', 'a', '1 Samuel 26:8-9 — "Then said Abishai to David, God hath delivered thine enemy into thine hand this day: now therefore let me smite him...But David said to Abishai, Destroy him not: for who can stretch forth his hand against the LORD''s anointed, and be guiltless?"'),
('1 Samuel', 26, 'teens', 3, 'David rebuked Abner the captain of Saul''s guard by calling out from the opposite hill. What failure did David accuse him of?', 'Failing to guard the king who was under his watch, so that someone had come in to destroy the LORD''s anointed', 'Spying on David''s camp and reporting David''s movements to Saul', 'Allowing the Ziphites to betray David''s hiding place to Saul', 'Killing innocent men on Saul''s orders without questioning them', 'a', '1 Samuel 26:15-16 — "And David said to Abner, Art not thou a valiant man?...wherefore then hast thou not kept thy lord the king?...as the LORD liveth, ye are worthy to die, because ye have not kept your master, the LORD''s anointed."'),
('1 Samuel', 26, 'teens', 4, 'What two possible explanations did David offer Saul for why Saul was persecuting him?', 'Either the LORD had stirred Saul against David — in which case God might be appeased with an offering — or men had incited Saul, in which case they were cursed before the LORD', 'Either Saul was deceived by false reports or Saul was genuinely righteous in his pursuit', 'Either David had sinned against Saul unknowingly or there were enemies within Saul''s camp', 'Either the Philistines had bribed Saul''s advisors or the spirit of Eli''s curse had fallen on Saul', 'a', '1 Samuel 26:19 — "If the LORD have stirred thee up against me, let him accept an offering: but if they be the children of men, cursed be they before the LORD."'),
('1 Samuel', 26, 'teens', 5, 'What did David say that showed he felt being driven out of Israel was like being told to worship other gods?', 'He said they were telling him to go serve other gods, as though being exiled from Israel''s land was the same as being cut off from the LORD''s inheritance', 'He said he could not worship in Philistia because the tabernacle was in Israel', 'He said that without the prophet Samuel he had no way to hear from God outside the land', 'He said the ark was in Israel and without it God could not hear his prayers in exile', 'a', '1 Samuel 26:19 — "they have driven me out this day from abiding in the inheritance of the LORD, saying, Go, serve other gods."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 26, 'adults', 1, 'How does the "deep sleep from the LORD" (26:12) compare to other divinely-induced sleeps in the Old Testament, and what does it suggest about the chapter''s theology of protection?', 'Divine deep sleep (_tardemah_) appears at creation (Gen. 2:21, Adam), at covenant-making (Gen. 15:12, Abram), and here at protection — in each case God acts while the human is rendered passive; the chapter argues David''s protection was not primarily his tactical skill but divine immobilization of the threat', 'The deep sleep is a naturalistic detail about Saul''s army being exhausted from marching', 'Divine sleep in Scripture is always a sign of judgment rather than of protection', 'The deep sleep only affected the sentries and Saul himself was simply naturally asleep', 'a', '1 Samuel 26:12 — "a deep sleep from the LORD was fallen upon them." Genesis 15:12 — "a deep sleep fell upon Abram; and, lo, an horror of great darkness fell upon him." In both cases God acts within the sleep to accomplish his covenant purposes.'),
('1 Samuel', 26, 'adults', 2, 'How does chapter 26 parallel chapter 24 structurally, and what does the doubling accomplish in confirming David''s fitness for kingship?', 'Both chapters feature David at the mercy of circumstance favoring killing Saul, a companion urging action, David''s principled refusal citing "the LORD''s anointed," confrontation from a distance afterward, and Saul''s temporary remorse — the doubling demonstrates that David''s restraint is a consistent moral character trait, not a single fortunate impulse', 'The two chapters draw on the same historical source and the doubling is unintentional', 'Chapter 26 corrects chapter 24 by showing David was more careful the second time', 'The parallel exists only superficially and the two incidents differ too much for structural comparison', 'a', '1 Samuel 26:11 — "The LORD forbid that I should stretch forth mine hand against the LORD''s anointed." This verbatim echo of 24:6 confirms deliberate parallel structure — David''s theology is tested twice and proven consistent.'),
('1 Samuel', 26, 'adults', 3, 'David''s lament that exile from Israel is equivalent to being told to "go serve other gods" (26:19) reflects what understanding of the theology of land in ancient Israel?', 'The land of Israel was understood as the LORD''s special domain — his "inheritance" (_nahalah_) — where his covenant presence, sanctuary, and ordinances operated; to be exiled from it was effectively to be exiled from the sphere of covenant relationship, hence David''s equation of exile with paganism', 'David''s equation of exile with paganism was a rhetorical exaggeration for emotional effect', 'The theology of land in the OT allows no distinction between God''s presence in Israel versus outside it', 'David''s statement was culturally conventional without implying genuine theological belief', 'a', '1 Samuel 26:19 — "they have driven me out this day from abiding in the inheritance of the LORD, saying, Go, serve other gods." This theology underlies the lament psalms from exile (e.g., Ps. 137) and the prophetic promise of return (Jer. 31).'),
('1 Samuel', 26, 'adults', 4, 'Saul''s confession "I have sinned" in 26:21 is his third such confession in 1 Samuel (15:24; 15:30; 26:21). How does this pattern of repeated confession without reformation function in his characterization?', 'Saul''s three confessions are progressively emptied of content — the first was self-serving, the second reputation-preserving, and the third is emotional but still unaccompanied by behavioral change; the pattern shows a man capable of acknowledging truth verbally while constitutionally incapable of the metanoia that changes behavior', 'Saul''s three confessions demonstrate genuine progressive repentance that God ultimately accepted', 'The repetition of confession is a coincidence without characterization significance', 'Saul''s confessions were genuine but external circumstances prevented him from following through', 'a', '1 Samuel 26:21 — "I have sinned." Compare 15:24 — "I have sinned: for I have transgressed the commandment of the LORD" and 15:30 — "I have sinned: yet honour me now." Three confessions; no lasting change.'),
('1 Samuel', 26, 'adults', 5, 'What is the theological significance of David leaving the spear and water cruse behind rather than keeping them as trophies?', 'The spear (military power) and water cruse (life-sustaining provision) belonged to the LORD''s anointed — taking them would have been seizing royal authority before its divine appointment; David''s restraint in leaving both is a symbolic refusal to grasp at kingship before the appointed time', 'David left the weapons purely for practical reasons — carrying them would have slowed his escape', 'The spear and water cruse were too heavy for David and Abishai to carry silently', 'David left them as a gesture of contempt to show Saul they were useless against God''s protection', 'a', '1 Samuel 26:12 — "David took the spear and the cruse of water from Saul''s bolster." 26:16 — David uses them as evidence of Saul''s vulnerability rather than as trophies of his own power — taking and giving-back enacts a theology of deferred authority.'),
('1 Samuel', 26, 'adults', 6, 'How does David''s rebuke of Abner (26:15-16) function as an implicit statement about the responsibilities of those who guard the LORD''s anointed?', 'By telling Abner he deserves death for failing to protect the king, David establishes a principle that those entrusted with guarding sacred authority bear mortal accountability for its protection — a principle with implications for all who serve in protective roles within God''s covenant order', 'The rebuke is merely a taunt to embarrass Saul''s captain with no theological content', 'David''s rebuke of Abner shows David wanted to humiliate Saul''s army more than spare Saul''s life', 'The rebuke was a military lesson about night watches with no theological dimension', 'a', '1 Samuel 26:16 — "as the LORD liveth, ye are worthy to die, because ye have not kept your master, the LORD''s anointed." Ezekiel 33:6 applies the same death-accountability principle to watchmen who fail to warn Israel.'),
('1 Samuel', 26, 'adults', 7, 'Saul''s prophecy "thou shalt both do great things, and also shalt still prevail" (26:25) has the same structure as his earlier confessions — recognition followed by resumption of opposition. What does this reveal about prophetic knowledge and moral will?', 'Saul demonstrates the terrible possibility of knowing God''s will accurately while remaining unable or unwilling to submit to it — his prophetic acknowledgments are not accompanied by surrender; this is the condition described in James 2:19: "the devils also believe, and tremble" — correct theology without transforming allegiance', 'Saul''s prediction of David''s success represents genuine spiritual restoration at this point', 'The prophecy proves Saul had truly repented and only external forces prevented reconciliation with David', 'Saul''s statement was flattery rather than genuine prophetic acknowledgment', 'a', '1 Samuel 26:25 — "Blessed be thou, my son David: thou shalt both do great things, and also shalt still prevail. So David went on his way, and Saul returned to his place." The brevity of the farewell encodes the futility of the exchange.'),
('1 Samuel', 26, 'adults', 8, 'How does chapter 26 function as the final test of David''s fitness to rule before his departure to Philistia in chapter 27?', 'Chapter 26 is the climactic character trial — having twice refused to seize what providence seemed to offer, David is morally established as a king who will rule by divine grant rather than human grasping; his departure to Philistia immediately afterward is the paradoxical consequence of faithfulness — the most obedient man must go furthest into exile before the kingdom comes', 'Chapter 26 is a narrative filler before the important events of chapters 28-31', 'The test in chapter 26 is military rather than moral — David proves he can infiltrate enemy camps', 'David''s departure to Philistia in chapter 27 is a failure that chapter 26 cannot explain', 'a', '1 Samuel 26:25 and 27:1 — David passes the test, Saul departs, and immediately "David said in his heart, I shall now perish one day by the hand of Saul" — the proximity of his deepest fear to his greatest display of faith shows trust in God does not eliminate emotional reality.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 27, 'teens', 1, 'What was David''s reasoning for going to Philistia, as reported in verse 1?', 'He thought that if he stayed in Israel Saul would eventually catch him, but if he went to Philistia Saul would stop searching for him', 'He believed God had commanded him through a dream to seek refuge among the Gentiles', 'He planned to recruit a Philistine army to help him take Israel''s throne from Saul', 'He went to Philistia specifically to protect his family from Saul''s vengeance', 'a', '1 Samuel 27:1 — "David said in his heart, I shall now perish one day by the hand of Saul: there is nothing better for me than that I should speedily escape into the land of the Philistines; and Saul shall despair of me, to seek me any more in any coast of Israel."'),
('1 Samuel', 27, 'teens', 2, 'When David raided the southern peoples from his base at Ziklag, which three peoples did he strike?', 'The Geshurites, the Gezrites, and the Amalekites', 'The Philistines, the Moabites, and the Edomites', 'The Ammonites, the Hivites, and the Perizzites', 'The Jebusites, the Hittites, and the Midianites', 'a', '1 Samuel 27:8 — "And David and his men went up, and invaded the Geshurites, and the Gezrites, and the Amalekites: for those nations were of old the inhabitants of the land."'),
('1 Samuel', 27, 'teens', 3, 'Why did David leave no man or woman alive in the villages he raided, and what did he tell Achish instead?', 'He left none alive so no one could report his true targets to Achish; he told Achish he had raided against the south of Judah, the Jerahmeelites, or the Kenites', 'He killed all captives because Philistine law required it of allied soldiers', 'He left none alive to prevent them from joining Saul''s army against him', 'He reported his raids accurately to Achish including which peoples he had attacked', 'a', '1 Samuel 27:9-11 — "David smote the land, and left neither man nor woman alive...And Achish said, Whither have ye made a road to day? And David said, Against the south of Judah...And David saved neither man nor woman alive, to bring tidings to Gath."'),
('1 Samuel', 27, 'teens', 4, 'What did Achish conclude about David as a result of his apparent raids against Judah?', 'That David had made himself utterly odious to his people Israel and would be Achish''s servant forever', 'That David was the greatest warrior in all the Philistine confederation', 'That David was loyal enough to be made commander of all Philistine forces', 'That David had truly converted to Philistine allegiance and renounced his Israelite gods', 'a', '1 Samuel 27:12 — "And Achish believed David, saying, He hath made his people Israel utterly to abhor him; therefore he shall be my servant for ever."'),
('1 Samuel', 27, 'teens', 5, 'Why does the narrator note that Ziklag "pertaineth unto the kings of Judah unto this day" after recording how Achish gave it to David?', 'It connects the narrative to later Israelite history, showing David''s time in Philistia had a lasting legal consequence — Ziklag became a permanent royal holding of the Davidic dynasty', 'The note explains why Ziklag was later destroyed by the Philistines as a reprisal', 'The note is a scribal error that belongs to a different section about Solomon''s kingdom', 'It explains why Ziklag was neutral territory available to David even after he became king of Judah', 'a', '1 Samuel 27:6 — "Then Achish gave him Ziklag that day: wherefore Ziklag pertaineth unto the kings of Judah unto this day." This editorial aside connects the fugitive episode to the established monarchy.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 27, 'adults', 1, 'David''s statement "I shall now perish one day by the hand of Saul" (27:1) appears immediately after his greatest display of principled faith in chapter 26. What does this juxtaposition reveal about faith and human weakness?', 'The juxtaposition shows that moral courage in specific situations does not eliminate ongoing anxiety — David''s theology of divine protection coexists with acute fear of Saul; this is not hypocrisy but the authentic complexity of faith that operates alongside, not in replacement of, ordinary human emotion', 'The verse shows David''s faith had fundamentally collapsed after chapter 26', 'The juxtaposition is a chronological dislocation with no intended theological comment', 'David''s fear proves he was not the man of faith portrayed in chapter 26', 'a', '1 Samuel 27:1 — "David said in his heart, I shall now perish one day by the hand of Saul." The phrase "in his heart" marks this as private anxiety, not public policy — Psalms of this period (Ps. 56, 34) show the same tension between faith and fear.'),
('1 Samuel', 27, 'adults', 2, 'How does David''s systematic deception of Achish in chapter 27 present a moral problem within the larger narrative of "the man after God''s own heart"?', 'The narrative presents David''s deception without explicit moral commentary, yet the consequences — complete slaughter of civilians to prevent intelligence leaks and sustained lying to an ally — represent the moral cost of the compromised situation David has placed himself in; the text invites readers to recognize both the pragmatic logic and the ethical degradation of choosing Philistia', 'The text explicitly endorses David''s deception as justified by his anointed status and the cause of Israel', 'David''s deception of Achish was no different from wartime intelligence operations and is morally neutral', 'The narrative portrays David''s deception as a divinely-commanded strategy for surviving until the throne', 'a', '1 Samuel 27:10-12 — David lies consistently to Achish while Achish concludes "He hath made his people Israel utterly to abhor him." The narrative''s silence on divine approval or disapproval is itself significant — compare 22:22 where David explicitly owns the consequences of his deceptions.'),
('1 Samuel', 27, 'adults', 3, 'The peoples David raided — Geshurites, Gezrites, Amalekites — are described as "of old the inhabitants of the land" (27:8). What theological context does this phrase invoke?', 'These were remnant Canaanite and wilderness peoples whom Israel had been commanded to dispossess under the _herem_ principle of holy war — David''s raids are framed implicitly as delayed execution of covenant obligations that Saul had failed to provide against Amalek in chapter 15', 'The phrase is purely historical, placing the raids within a geographic context without covenant resonance', 'The peoples raided were enemies of Philistia and the covenant context is irrelevant', 'The phrase emphasizes that these peoples had no modern political status and could be raided without legal consequence', 'a', '1 Samuel 27:8 — "those nations were of old the inhabitants of the land, as thou goest to Shur, even unto the land of Egypt." The Amalekites appear specifically — the same people Saul failed to devote in chapter 15 — suggesting the raids complete what Saul left unfinished.'),
('1 Samuel', 27, 'adults', 4, 'How does the geographical notation "as thou goest to Shur, even unto the land of Egypt" (27:8) connect David''s raids to Abrahamic covenant history?', 'The "way to Shur" is the route Abraham and the patriarchs traveled — the boundary of Egypt where Ishmael''s descendants settled; David''s raids in this southern corridor echo the patriarchal narratives and implicitly connect his activity to the full sweep of the promised land''s extent', 'The geographical notation is a simple directional note with no patriarchal resonance', 'The Shur reference connects only to the Exodus narratives and has no Abrahamic dimension', 'David''s raids were limited to Philistine territory and never extended to the Egyptian border', 'a', 'Genesis 25:18 — "And they dwelt from Havilah unto Shur, that is before Egypt." 1 Samuel 15:7 uses the same boundary phrase for Saul''s Amalekite campaign — the repetition ties David''s raids to both patriarchal boundaries and Saul''s incomplete obedience.'),
('1 Samuel', 27, 'adults', 5, 'Achish''s conclusion that David "shall be my servant for ever" (27:12) is dramatically ironic in light of subsequent history. How does this irony function in the narrative?', 'Achish''s confident misreading of David''s deception — believing David has burned his bridges with Israel — is a further instance of the theme that pagan rulers consistently misunderstand the divine plan; Achish becomes an unwitting instrument who shelters Israel''s future king while believing he has permanently secured him as a vassal', 'Achish''s conclusion was partially correct since David did serve him for sixteen months', 'The irony is tragic rather than providential — David nearly became a Philistine client permanently', 'Achish''s reading of the situation was more accurate than the narrative acknowledges', 'a', '1 Samuel 27:12 — "Achish believed David, saying, He hath made his people Israel utterly to abhor him." Acts 4:27-28 expresses the same theological principle: human opposition and misunderstanding are incorporated into God''s sovereign plan.'),
('1 Samuel', 27, 'adults', 6, 'The sixteen months in Philistia represent the longest gap in the Saul-David conflict. What does this extended sojourn contribute to the theology of waiting in the David narratives?', 'The sixteen months demonstrate that the path to the promised throne runs through the wilderness of apparent abandonment — David must wait not just in the Judean wilderness but in pagan territory before the kingdom comes; this protracted exile deepens the typological pattern of the true king who passes through humiliation before exaltation', 'The sixteen months are simply historical duration with no theological significance', 'The extended stay in Philistia was a lapse in David''s faith that God graciously reversed', 'The sojourn demonstrates primarily tactical wisdom rather than theological waiting', 'a', '1 Samuel 27:7 — "the time that David dwelt in the country of the Philistines was a full year and four months." Psalm 13:1 — "How long wilt thou forget me, O LORD? for ever?" — the psalms of this period articulate the theology of extended waiting as a school of faith.'),
('1 Samuel', 27, 'adults', 7, 'How does David''s strategy of total slaughter to prevent intelligence leaks (27:9-11) compare to his own earlier moral reasoning about not shedding innocent blood in chapter 25?', 'The comparison reveals a moral trajectory — in chapter 25 David was restrained from shedding "causeless blood" by Abigail; in chapter 27 he sheds civilian blood systematically for strategic reasons; the Philistian period represents a moral compromise in which survival logic has displaced the theological restraint that characterized him in Judah', 'The two situations are morally incomparable because 27:9-11 involves enemies of Israel while 25:33 involved a kinsman', 'David''s actions in 27:9-11 were explicitly commanded by God and carry no moral problem', 'The narrative endorses the slaughter as necessary and contrasts it favorably with Saul''s incomplete warfare', 'a', '1 Samuel 25:33 — "which hast kept me this day from coming to shed blood, and from avenging myself." 27:11 — "David saved neither man nor woman alive." The contrast is the text''s implicit moral comment on what exile from Israel''s covenant community costs.'),
('1 Samuel', 27, 'adults', 8, 'How does chapter 27 as a whole function as the narrative''s darkest moral moment before David''s restoration?', 'Chapter 27 places David furthest from everything that defines him — he is in Philistia not Israel''s inheritance, living by deception not by the word of God, serving a pagan king not the LORD, and massacring peoples he should protect; this total inversion of his vocation is the nadir that chapters 29-30 and 2 Samuel 2-5 will progressively reverse', 'Chapter 27 shows David at the peak of his strategic wisdom and is the high point of his fugitive career', 'The chapter presents David''s time in Philistia as morally neutral pragmatism rather than a spiritual nadir', 'Chapter 27 is the narrative''s resolution of the Saul-David conflict rather than its lowest point', 'a', '1 Samuel 27:1 — "I shall now perish one day by the hand of Saul." The fear that drives David to Philistia is the first line; the deception and slaughter that sustain him there are its logical extensions — until God intervenes through the Philistine rejection of ch. 29 and the Amalekite raid of ch. 30.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 28, 'teens', 1, 'Why could Saul not get an answer from the LORD before the battle with the Philistines?', 'The LORD did not answer him by dreams, Urim, or prophets — because Saul had disobeyed God and God had departed from him', 'The ark of the covenant had been captured and no inquiry was possible without it', 'Samuel was dead and no other prophet existed who could relay God''s word', 'Saul had not fasted for three days as the law required before seeking an oracle', 'a', '1 Samuel 28:6 — "And when Saul enquired of the LORD, the LORD answered him not, neither by dreams, nor by Urim, nor by prophets."'),
('1 Samuel', 28, 'teens', 2, 'Why was it especially ironic that Saul sought out a medium at En-dor?', 'Saul himself had previously expelled all mediums and wizards from the land in obedience to God''s law, so he was now going to the very kind of practitioner he had outlawed', 'Saul had built the woman''s house personally during a campaign years earlier', 'The medium was a relative of Samuel and had personally known the prophet', 'Saul had never before believed in the power of mediums and this was a complete reversal of his worldview', 'a', '1 Samuel 28:3,9 — "And Saul had put away those that had familiar spirits, and the wizards, out of the land...And the woman said unto him, Behold, thou knowest what Saul hath done, how he hath cut off those that have familiar spirits, and the wizards, out of the land."'),
('1 Samuel', 28, 'teens', 3, 'When Samuel''s spirit appeared, what did he say to Saul about the reason for his abandonment by God?', 'Because Saul had not obeyed the voice of the LORD and had not executed his fierce wrath upon Amalek, the LORD had taken the kingdom from him and given it to David', 'Because Saul had consulted a medium, God was removing his blessing immediately', 'Because Saul had driven David away and broken his covenant with Jonathan''s family', 'Because Saul had failed to build the temple that God had commanded him to construct', 'a', '1 Samuel 28:18 — "Because thou obeyedst not the voice of the LORD, nor executedst his fierce wrath upon Amalek, therefore hath the LORD done this thing unto thee this day."'),
('1 Samuel', 28, 'teens', 4, 'What happened to Saul physically when he heard Samuel''s pronouncement?', 'He fell straightway all along on the earth and was greatly afraid, and there was no strength in him, for he had eaten no bread all that day and night', 'He wept uncontrollably and tore his royal robes', 'He fainted and had to be revived by his servants with cold water', 'He became very angry and threatened the medium for giving him bad news', 'a', '1 Samuel 28:20 — "Then Saul fell straightway all along on the earth, and was sore afraid, because of the words of Samuel: and there was no strength in him; for he had eaten no bread all the day, nor all the night."'),
('1 Samuel', 28, 'teens', 5, 'What did the medium of En-dor do for Saul before he left, and what does this detail reveal about her?', 'She killed a fat calf, baked unleavened bread, and fed Saul and his servants — an act of surprising hospitality and compassion toward the king who had outlawed her profession', 'She demanded payment of gold and silver before she would feed him', 'She gave Saul a prophetic word of her own promising he would be saved', 'She sent a messenger to tell the Philistines where Saul had been that night', 'a', '1 Samuel 28:24-25 — "And the woman had a fat calf in the house; and she hasted, and killed it, and took flour, and kneaded it, and did bake unleavened bread thereof: And she brought it before Saul, and before his servants; and they did eat."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 28, 'adults', 1, 'The three-channel silence of 28:6 — no dreams, no Urim, no prophets — represents what in terms of covenant communication?', 'God''s threefold refusal marks the complete severance of every legitimate channel of divine revelation from Saul — the same channels that served David and the patriarchs; the silence is not absence of God but judgment made audible through cessation, fulfilling the warning of Proverbs 1:28: "Then shall they call upon me, but I will not answer."', 'The threefold silence was a temporary testing of Saul rather than a permanent rejection', 'The absence of prophetic word was because all prophets had fled to David''s camp', 'The Urim and Thummim were lost when Doeg killed the priests and could not function without a legitimate high priest', 'a', '1 Samuel 28:6 — "the LORD answered him not, neither by dreams, nor by Urim, nor by prophets." Compare 1 Samuel 3:1 — "the word of the LORD was precious in those days; there was no open vision" — silence as theological verdict appears repeatedly in Samuel.'),
('1 Samuel', 28, 'adults', 2, 'How does Saul''s consultation of the medium at En-dor represent the culminating irony of his reign, given the law of Deuteronomy 18?', 'The king who was supposed to model covenant fidelity and enforce Deuteronomy''s prohibition of necromancy (Deut. 18:10-12) — and who had himself expelled mediums from Israel (28:3) — now commits the very capital abomination he had outlawed, seeking the dead because the living God will not answer; his reign ends in the precise sin it tried to eradicate', 'Saul''s visit to the medium was a private sin with no connection to his public enforcement of the law', 'Deuteronomy 18 did not specifically prohibit kings from consulting mediums', 'The irony is incidental — Saul had no better option available and the text does not judge him for it', 'a', 'Deuteronomy 18:10-12 — "There shall not be found among you any one that...useth divination, or an observer of times, or an enchanter, or a witch...For all that do these things are an abomination unto the LORD." 1 Samuel 28:3 — Saul himself had enacted this law; now he breaks it.'),
('1 Samuel', 28, 'adults', 3, 'The question of whether the apparition at En-dor was the genuine Samuel or a demonic deception is one of the most debated passages in the OT. What textual evidence supports the genuine Samuel interpretation?', 'The narrator says unambiguously "Samuel said" (not "the spirit said"), Samuel''s words perfectly replicate the earlier prophecy of 15:28, the medium herself is terrified by what appears (suggesting it exceeded her normal experience), and Samuel provides accurate predictive information — all pointing to a genuine divine accommodation rather than demonic mimicry', 'The text explicitly states the apparition was a demon impersonating Samuel', 'The medium''s calm response proves she recognized it as a routine familiar spirit rather than Samuel', 'The theological impossibility of the dead speaking means the apparition must have been a deception regardless of the text''s language', 'a', '1 Samuel 28:12,15-16 — "And when the woman saw Samuel...And Samuel said to Saul, Why hast thou disquieted me, to bring me up?...the LORD is departed from thee, and is become thine enemy." The medium''s terror (v.12) distinguishes this from her ordinary practice.'),
('1 Samuel', 28, 'adults', 4, 'Samuel''s message in 28:16-19 contains no new theological content — it simply repeats what was already prophesied in chapters 13 and 15. What is the theological function of this repetition at the moment of death?', 'The repetition at the threshold of death strips away any lingering ambiguity — what had been prophecy becomes announcement; the same word that Saul rejected in life becomes the verdict that closes his reign in death; the word of God proves inalterable regardless of how long a rebellious king ignores it', 'The repetition shows Samuel was unable to deliver any new revelation from the afterlife', 'The lack of new content suggests the apparition was a projection of Saul''s own guilty conscience', 'Samuel repeated the old prophecy to comfort Saul by reminding him the situation was not his fault', 'a', '1 Samuel 28:17-18 — "the LORD hath done to him, as he spake by me: for the LORD hath rent the kingdom out of thine hand, and given it to thy neighbour, even to David: Because thou obeyedst not the voice of the LORD." Isaiah 40:8 — "the word of our God shall stand for ever."'),
('1 Samuel', 28, 'adults', 5, 'The phrase "thou and thy sons shall be with me" (28:19) — spoken by Samuel — has generated discussion about what it implies regarding Saul''s afterlife. What does the phrase most naturally suggest in context?', 'Samuel says "with me" — meaning in the realm of the dead where Samuel now is — not explicitly "in torment" or "in peace"; the phrase is ambiguous about the moral quality of Saul''s afterlife while being certain about his immediate death, a restrained OT eschatology that does not adjudicate what lies beyond Sheol', 'The phrase clearly implies Saul will be in the same blessed state as Samuel', 'The phrase explicitly condemns Saul to eternal punishment alongside his sons', 'The phrase means only that Saul''s body will be buried near Samuel''s tomb at Ramah', 'a', '1 Samuel 28:19 — "to morrow shalt thou and thy sons be with me." The use of _immi_ ("with me") rather than any evaluative term reflects the OT''s characteristically reserved eschatological language for Sheol as the neutral gathering place of the dead.'),
('1 Samuel', 28, 'adults', 6, 'How does chapter 28 function as a structural interlude in the narrative, being placed between the Philistine muster (ch. 28:1-2) and its resumption (ch. 29)?', 'The chapter is a deliberate "time-dilation" — the narrative slows to give Saul''s interior collapse its full moral weight before the battle; the reader witnesses the king''s spiritual death before his physical death, making chapter 31''s battlefield report the external confirmation of what 28 has already announced', 'The chapter''s placement is a result of different source materials being interleaved with no editorial intention', 'The interlude exists only to explain why Saul was weakened before the battle', 'Chapter 28 is chronologically after chapter 31 and was inserted here by a later editor', 'a', '1 Samuel 28:19 — "to morrow shalt thou and thy sons be with me." The death is announced in chapter 28; executed in chapter 31 — the narrative holds both together, ensuring the reader understands Saul''s death as fulfillment of divine word.'),
('1 Samuel', 28, 'adults', 7, 'The medium''s act of feeding Saul (28:24-25) has been compared to Elijah''s feeding in the wilderness (1 Kings 19:5-8) and to other meals at turning points in Scripture. What does the meal signify here?', 'The meal is sustenance for a condemned man''s final journey — the medium''s compassion does not change Saul''s fate but it humanizes him in his darkest hour; the bread baked and the calf slaughtered mirror hospitality traditions throughout the ancient Near East, underscoring that even God''s enemies receive ordinary human dignity', 'The meal signifies Saul''s restoration to physical health and reversal of his weakness', 'The medium fed Saul as a payment for the consultation rather than out of compassion', 'The meal has no symbolic dimension and is simply a practical necessity for Saul''s return journey', 'a', '1 Samuel 28:22 — "Now therefore, I pray thee, hearken thou also unto the voice of thine handmaid, and let me set a morsel of bread before thee; and eat, that thou mayest have strength, when thou goest on thy way." The medium''s insistence on feeding the dying king is one of Scripture''s quiet acts of grace toward the condemned.'),
('1 Samuel', 28, 'adults', 8, 'How does Saul''s visit to the witch of En-dor represent the theological endpoint of his trajectory from chapter 10 — where the Spirit of God came upon him — to chapter 28?', 'Saul''s journey from Spirit-filled prophet-king (10:10-11) to seeker of dead spirits (28:7) traces a complete spiritual inversion: the man upon whom God''s Spirit descended now pursues a forbidden spirit because God''s Spirit has departed; the career arc from Pentecost-type anointing to necromancy is the canon''s sharpest portrait of apostasy''s destination', 'Saul''s trajectory was primarily political rather than spiritual and the En-dor episode is only incidentally related to his anointing', 'The Spirit''s departure from Saul in chapter 16 was temporary and chapter 28 shows him trying to restore the connection through legitimate if unusual means', 'Saul''s arc is tragic but not apostasy since he never formally renounced the LORD', 'a', '1 Samuel 10:10 — "the Spirit of God came upon him, and he prophesied." 16:14 — "the Spirit of the LORD departed from Saul." 28:7 — Saul seeks a familiar spirit. The three verses are the structural skeleton of his entire spiritual biography.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 29, 'teens', 1, 'What accusation did the Philistine lords make against David when they saw him marching with Achish?', 'They said David was the one of whom Israelite women sang "Saul hath slain his thousands, and David his ten thousands" and feared he would become an adversary in battle', 'They accused David of having sent a spy to warn Israel of the battle plan', 'They said David had stolen weapons from the Philistine armory at Gath', 'They claimed David was still secretly communicating with Jonathan against the Philistines', 'a', '1 Samuel 29:4-5 — "Make this fellow return...lest in the battle he be an adversary to us...Is not this David, of whom they sang one to another in dances, saying, Saul hath slain his thousands, and David his ten thousands?"'),
('1 Samuel', 29, 'teens', 2, 'How did Achish defend David to the other Philistine lords?', 'He said he had found no fault in David since the day he came to him, just as an angel of God would be, and that David should march in front of him', 'He said David had proven his loyalty by raiding Israelite villages for months', 'He threatened to punish any lord who questioned David''s loyalty', 'He argued that David''s six hundred men were indispensable for the coming battle', 'a', '1 Samuel 29:9 — "And Achish answered and said to David, I know that thou art good in my sight, as an angel of God: notwithstanding the princes of the Philistines have said, He shall not go up with us to the battle."'),
('1 Samuel', 29, 'teens', 3, 'How did David respond to being sent away — did his words suggest he was relieved or reluctant?', 'David''s response was formally reluctant — asking "what have I done?" and asserting his desire to fight against the king''s enemies — which could be read as either genuine protest or diplomatic face-saving while being relieved of a terrible dilemma', 'David was openly relieved and thanked Achish for releasing him from the obligation', 'David was angry and demanded to know which lord had accused him', 'David wept and refused to leave until Achish personally escorted him', 'a', '1 Samuel 29:8 — "And David said unto Achish, But what have I done? and what hast thou found in thy servant so long as I have been with thee unto this day, that I may not go fight against the enemies of my lord the king?"'),
('1 Samuel', 29, 'teens', 4, 'How many days did David and his men travel before arriving back at Ziklag?', 'They rose up early on the third day and came to Ziklag', 'They arrived back in one day since Ziklag was nearby', 'They took a week to return because they were marching with heavy supplies', 'They arrived after five days, resting on the Sabbath along the way', 'a', '1 Samuel 30:1 — "And it came to pass, when David and his men were come to Ziklag on the third day." The three-day journey from Aphek to Ziklag frames the dramatic discovery.'),
('1 Samuel', 29, 'teens', 5, 'What is the theological significance of the Philistine lords unwittingly rescuing David from the impossible dilemma of fighting against Israel?', 'God used pagan opposition to accomplish what David''s own faith could not resolve — the lords'' refusal providentially extracted David from a situation where every option was sin, showing that divine protection operates even through enemies who intend no favor', 'The episode shows David''s superior diplomatic skills enabled him to escape the dilemma himself', 'The chapter is a purely historical episode with no providential theology', 'The lords were moved by divine compassion for David rather than by suspicion of him', 'a', '1 Samuel 29:10 — "Wherefore now rise up early in the morning with thy master''s servants that are come with thee: and as soon as ye be up early in the morning, and have light, depart." Had David fought against Israel, he could not have been the king of Israel — the rejection was providential rescue.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 29, 'adults', 1, 'Chapter 29 is an intercalation — inserted between the muster of 28:1 and the battle of chapter 31. What is the narrative and theological effect of this placement?', 'The intercalation creates simultaneous dramatic irony: while Saul consults a dead prophet in darkness (ch. 28) and marches toward death, David is being providentially extracted from the same battle by pagan lords; the two tracks — death and preservation — run parallel, and the intercalation makes their contrast structurally visible', 'Chapter 29 is misplaced and belongs chronologically after chapter 31', 'The intercalation exists only because the text was compiled from multiple sources without editorial coordination', 'The placement is designed to slow the narrative pace with no theological intention', 'a', '1 Samuel 28:1 — "the Philistines gathered their armies together for warfare" — the muster begins; 29:1 — "Now the Philistines gathered together all their armies" — the same muster resumed; ch. 28 (Saul) and ch. 29 (David) are simultaneous tracks made sequential.'),
('1 Samuel', 29, 'adults', 2, 'Achish''s comparison of David to "an angel of God" (29:9) is ironic in multiple directions. How does the text deploy this irony?', 'Achish uses the highest honorific of trustworthiness to describe a man who has been systematically deceiving him for sixteen months — the comparison confirms Achish''s complete blindness while the reader knows that David''s "angelic" trustworthiness is entirely performed; simultaneously the reader may recognize that God has indeed used David as an angelic instrument of providential rescue for Israel', 'Achish''s comparison was an accurate assessment of David''s character at this point in the narrative', 'The "angel of God" comparison is a standard diplomatic formula with no specific ironic dimension', 'Achish used the comparison to make the Philistine lords feel they were insulting a divine figure', 'a', '1 Samuel 29:9 — "thou art good in my sight, as an angel of God." The reader of 27:10-12 knows David''s angelic reputation with Achish is built entirely on fabrication — the irony is one of the sharpest in the David narrative.'),
('1 Samuel', 29, 'adults', 3, 'David''s protest "what have I done?" (29:8) echoes his earlier speech to Saul in 17:29. What does this verbal echo suggest about David''s rhetorical character?', 'David habitually deploys formal protest of innocence regardless of actual guilt — in 17:29 before Eliab, in 24:9 before Saul, and now before Achish; the formula of indignant innocence is a consistent rhetorical strategy that David uses whether he is genuinely innocent or performing a role, revealing the complex relationship between his authentic self-understanding and his tactical self-presentation', 'The echo is coincidental and the phrase was simply a common Hebrew expression of protest', 'David''s protest to Achish was entirely sincere because he genuinely wanted to fight alongside the Philistines', 'The verbal echo shows David''s speeches were composed by the same scribe for literary consistency', 'a', '1 Samuel 17:29 — "What have I now done?" 29:8 — "But what have I done?" The rhetorical formula of wounded innocence recurs across David''s career, sometimes genuine, sometimes strategic.'),
('1 Samuel', 29, 'adults', 4, 'What does the Philistines'' song ("Saul hath slain his thousands, and David his ten thousands") accomplish when it appears for the third time in 1 Samuel (18:7; 21:11; 29:5)?', 'Each repetition deepens the irony: in 18:7 the song creates the rift between Saul and David; in 21:11 it threatens David''s life in Gath; in 29:5 it saves his life by getting him expelled from the Philistine muster — the same song that endangered David with his own king now providentially protects him by making him unwelcome among Israel''s enemies', 'The three repetitions are a formulaic device that simply marks David''s growing fame without narrative significance', 'The third repetition in chapter 29 is the least significant of the three', 'The song was originally a Philistine composition about their own enemies that Israel adopted', 'a', '1 Samuel 18:7 — the song that turned Saul against David; 21:11 — the song that put David in danger in Gath; 29:5 — the song that expelled him from the battle. A single song drives the entire Saul-David-Philistine triangle.'),
('1 Samuel', 29, 'adults', 5, 'What does Achish''s inability to override his own lords'' decision (29:4-9) suggest about the limits of royal authority in Philistine polity compared to Israel''s monarchy?', 'The Philistine confederation operated as a council of five lords (_seranim_) with collective authority that constrained even their most trusted king — Achish cannot protect David against the lords'' consensus; this contrasts with Israel''s constitutional monarchy under the Torah, where the king was supposed to be bound by God''s law rather than by aristocratic consensus', 'Achish was simply weak compared to other Philistine kings and the episode reflects personal rather than structural limitation', 'The Philistine political structure was identical to Israel''s and the episode has no comparative political significance', 'Achish chose to defer to his lords as a diplomatic courtesy rather than because they had binding authority', 'a', '1 Samuel 29:4 — "And the princes of the Philistines were wroth with him." 29:9 — "the princes of the Philistines have said, He shall not go up with us to the battle." The lords'' authority over Achish on this matter is determinative — Achish cannot override it.'),
('1 Samuel', 29, 'adults', 6, 'The instruction "rise up early in the morning, and have light, depart" (29:10) creates what kind of contrast with chapter 28''s darkness?', 'While Saul traveled to En-dor in darkness and disguise (28:8) — both literal and spiritual — David departs in early morning light; the chapter deploys the biblical symbolism of darkness as spiritual deception and light as divine ordering, contrasting the trajectories of the two kings even through physical descriptions of their movements', 'The instruction to depart at dawn is purely practical and carries no light-darkness symbolism', 'The contrast of light and darkness is coincidental since the chapter''s author had no knowledge of chapter 28', 'The early morning departure signifies shame — being expelled at dawn was a form of public humiliation', 'a', '1 Samuel 28:8 — "Saul disguised himself...and he went, and two men with him, and they came to the woman by night." 29:10 — "rise up early in the morning, and have light, depart." Night versus morning light frames the two kings'' moral situations.'),
('1 Samuel', 29, 'adults', 7, 'How does chapter 29 resolve David''s otherwise insoluble ethical dilemma without making David the moral agent of resolution?', 'David is passive — he neither engineers his release nor refuses to march; the resolution comes entirely from outside him (the lords'' objection), preserving both his appearance of loyalty to Achish and his freedom from fighting Israel; God''s providence resolves the dilemma so David does not have to — a pattern of divine rescue-through-others found throughout the psalms', 'David secretly communicated with the Philistine lords to arrange his own expulsion', 'David resolved the dilemma himself by deliberately performing poorly in the initial muster parade to raise suspicion', 'The chapter implies David would have fought against Israel if not expelled, showing his faith had collapsed', 'a', '1 Samuel 29:11 — "So David and his men rose up early to depart in the morning." David''s role is to rise and depart — the resolution is handed to him; compare Psalm 121:3 — "He that keepeth thee will not slumber."'),
('1 Samuel', 29, 'adults', 8, 'How does the repeated emphasis on David''s integrity in Achish''s speeches (29:6,9) function within the larger ironic framework of chapters 27-29?', 'Achish''s sincere attestations of David''s perfect integrity form the novel''s sustained dramatic irony: the reader who knows chapter 27''s deceptions watches a trusting pagan king testify to the honesty of a man who has been lying to him continuously — the gap between Achish''s perception and narrative reality is the text''s devastating commentary on how completely David''s Philistine period compromised his character', 'Achish''s attestations are accurate and David did maintain complete integrity in his dealings with Gath', 'The irony of Achish praising David''s integrity is incidental rather than a deliberate authorial strategy', 'Achish''s praises were insincere flattery designed to soften the blow of David''s expulsion', 'a', '1 Samuel 29:6 — "thou hast been upright, and thy going out and thy coming in with me in the host is good in my sight." The reader knows from 27:10-12 that every report David gave Achish was fabricated — Achish''s "upright" is the most innocent compliment in the darkest possible situation.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 30, 'teens', 1, 'How did David find out which direction to pursue the Amalekites?', 'He enquired of the LORD through Abiathar the priest using the ephod, and God told him to pursue and that he would recover all', 'He followed the tracks left by the Amalekite camels in the sand', 'He sent out scouts in three directions and waited for their report', 'He found an Amalekite prisoner at Ziklag who revealed the route', 'a', '1 Samuel 30:7-8 — "And David said to Abiathar the priest, Ahimelech''s son, I pray thee, bring me hither the ephod...And David enquired at the LORD, saying, Shall I pursue after this troop? shall I overtake them? And he answered him, Pursue: for thou shalt surely overtake them, and without fail recover all."'),
('1 Samuel', 30, 'teens', 2, 'Who helped David find the Amalekite camp after being found in a field near exhaustion?', 'An Egyptian servant who had been abandoned by his Amalekite master when he fell sick', 'A Kenite shepherd who had seen the Amalekites pass by with the captives', 'A Jerahmeelite merchant who had traded with the Amalekites recently', 'A wounded Israelite soldier who had survived the raid on Ziklag', 'a', '1 Samuel 30:11,13 — "And they found an Egyptian in the field, and brought him to David...And David said unto him, To whom belongest thou? and whence art thou? And he said, I am a young man of Egypt, servant to an Amalekite; and my master left me, because three days agone I fell sick."'),
('1 Samuel', 30, 'teens', 3, 'How many of the Amalekites escaped from the battle, and how did they escape?', 'Four hundred young men rode away on camels and escaped', 'Two hundred Amalekites fled on horseback into the wilderness', 'Only the Amalekite king escaped in a chariot with his royal guard', 'Three hundred Amalekites dispersed into the hills before David could surround them', 'a', '1 Samuel 30:17 — "And David smote them from the twilight even unto the evening of the next day: and there escaped not a man of them, save four hundred young men, which rode upon camels, and fled."'),
('1 Samuel', 30, 'teens', 4, 'When David returned with the spoil, some of his men who had fought refused to share with the two hundred who had been too exhausted to cross the brook Besor. What rule did David establish?', 'That he who tarries by the stuff shall share equally with he who goes to battle — making it a statute and ordinance for Israel forever', 'That those who fought would receive a double portion while those who stayed received a single share', 'That only those who actually fought could receive any portion of the recovered possessions', 'That the exhausted men would receive their own possessions back but no share of the additional spoil', 'a', '1 Samuel 30:24-25 — "as his part is that goeth down to the battle, so shall his part be that tarrieth by the stuff: and it shall be alike. And it was so from that day forward, that he made it a statute and an ordinance for Israel."'),
('1 Samuel', 30, 'teens', 5, 'To whom did David send portions of the recovered spoil, and what was his stated reason?', 'He sent to the elders of Judah in various cities saying it was a present of the spoil of the enemies of the LORD — building political goodwill across Judah before he became king', 'He sent spoil to Achish as proof of his loyalty to Gath before returning to Israel', 'He sent portions to Abiathar the priest to redistribute among the priests of Israel', 'He sent spoil only to his own tribe in Bethlehem as an honor to his family', 'a', '1 Samuel 30:26 — "And when David came to Ziklag, he sent of the spoil unto the elders of Judah, even to his friends, saying, Behold a present for you of the spoil of the enemies of the LORD."');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 30, 'adults', 1, 'The phrase "David encouraged himself in the LORD his God" (30:6) is one of the most quoted phrases in the book. What is the Hebrew and what does it specifically imply?', 'The Hebrew _yitchazzeq_ means to strengthen or harden oneself — the same root used of God strengthening Joshua (Josh. 1:6-9); David''s act is not merely emotional self-talk but a theological act of re-anchoring his identity and hope in covenant relationship with God when all external supports (family, men''s loyalty, city) had collapsed', 'The phrase means David gave an encouraging speech to his men to restore their morale', 'The Hebrew implies David went into a trance-like prophetic state to receive divine comfort', 'The phrase describes David praying for emotional stability with no active faith component', 'a', '1 Samuel 30:6 — "but David encouraged himself in the LORD his God." Joshua 1:7 — "Only be thou strong and very courageous." The same root (_chazaq_) appears in God''s command to Joshua — David applies to himself the command God gave his predecessor.'),
('1 Samuel', 30, 'adults', 2, 'Chapter 30 is a structural mirror of chapter 27: in chapter 27 David attacked southern peoples and lied about it; in chapter 30 he is attacked by a southern people and God enables total recovery. What does this structural reversal suggest?', 'The reversal enacts a kind of narrative justice — the Amalekites David had attacked now attack him; but more importantly, chapter 30 shows David operating with complete transparency (enquiring of God, sharing spoil according to divine principle) after the opacity of chapter 27, marking his moral restoration before the narrative closes', 'The parallel between chapters 27 and 30 is incidental and the structure argues no moral lesson', 'Chapter 30 shows David was punished for his deceptions in chapter 27 through the Amalekite raid', 'The structural reversal proves David''s actions in chapter 27 were divinely approved since he suffered no lasting harm', 'a', '1 Samuel 27:8 — David raids Amalekites among others; 30:1 — Amalekites raid David. The symmetry is narrative theology — what you sow, the world reflects back.'),
('1 Samuel', 30, 'adults', 3, 'The Egyptian slave abandoned by his master when sick (30:11-13) functions as what kind of narrative element, and what does he represent theologically?', 'He is the providential instrument through whom God guides David to the Amalekite camp — an abandoned, nationless, sick slave becomes the key to total victory; the episode demonstrates that God''s instruments of deliverance are characteristically the weak and cast-off rather than the powerful, a pattern central to OT and NT theology', 'The Egyptian is purely a narrative mechanism to solve the plot problem of locating the Amalekites', 'The Egyptian represents the pagan world acknowledging Israel''s military superiority', 'The abandoned slave is an incidental detail that adds historical color without theological significance', 'a', '1 Samuel 30:13-15 — an Egyptian slave abandoned when sick becomes the guide to total recovery. Cf. 1 Corinthians 1:27 — "God hath chosen the weak things of the world to confound the things which are mighty."'),
('1 Samuel', 30, 'adults', 4, 'How does David''s equal-shares statute (30:24-25) reflect and advance the principles of covenant community established in the Mosaic law?', 'The statute embodies the Mosaic principle that all members of the covenant community — including those whose role is support rather than combat — have equal claim to the community''s blessing; David extends what Numbers 31:27 established (Moses'' rule of dividing spoil equally between fighters and the congregation) and gives it permanent legal force as "a statute and an ordinance for Israel"', 'David''s rule was entirely original with no relationship to Mosaic precedent', 'The statute was a pragmatic political decision to prevent mutiny rather than a theological principle', 'David''s rule contradicts Mosaic law which explicitly required fighters to receive more than non-combatants', 'a', '1 Samuel 30:25 — "he made it a statute and an ordinance for Israel." Numbers 31:27 — "And divide the prey into two parts; between them that took the war upon them, who went out to battle, and between all the congregation." David codifies Moses'' precedent.'),
('1 Samuel', 30, 'adults', 5, 'David''s distribution of spoil to the elders of Judah (30:26-31) visits exactly seventeen cities or regions. What does this carefully catalogued distribution signify politically and theologically?', 'The seventeen-city distribution is a map of David''s political investment in his own tribe''s leadership — each gift builds loyalty among the very people who will anoint him king of Judah in 2 Samuel 2; theologically it is "a present of the spoil of the enemies of the LORD," framing political consolidation as covenant victory shared with the community', 'The distribution was random generosity with no political calculation', 'The distribution was a guilt offering for David''s time among the Philistines', 'The list of cities is a later scribal addition with no connection to the original narrative', 'a', '1 Samuel 30:26-31 — "he sent of the spoil unto the elders of Judah, even to his friends." 2 Samuel 2:4 — "the men of Judah came, and there they anointed David king over the house of Judah." The recipients of spoil in ch. 30 become the anointing community of 2 Sam. 2.'),
('1 Samuel', 30, 'adults', 6, 'How does chapter 30 function as David''s final examination before the crown, completing the testing sequence that began in chapter 21?', 'Chapters 21-30 have tested David''s integrity under pressure in every domain — personal safety (21), loyalty (22), justice (23-24), mercy (25-26), faithfulness (27-29), and now leadership under total loss (30); in chapter 30 he passes the most comprehensive test — facing the hatred of his own men and the ruin of everything — by turning immediately to God, and he emerges with full recovery and generosity intact', 'Chapter 30 is simply the last event before Saul''s death and has no testing significance', 'David''s testing was complete at chapter 26 and chapter 30 is an epilogue', 'The testing sequence in 1 Samuel is not structured thematically but chronologically', 'a', '1 Samuel 30:6 — "David was greatly distressed; for the people spake of stoning him...but David encouraged himself in the LORD his God." The king who can govern his own heart under maximum pressure can govern a nation — the test is passed.'),
('1 Samuel', 30, 'adults', 7, 'The Amalekite raid and recovery in chapter 30 deliberately echoes Saul''s incomplete destruction of the Amalekites in chapter 15. What does the echo suggest about the theology of incomplete obedience?', 'The echo demonstrates that incomplete obedience has permanent consequences — Saul''s failure to destroy Amalek in chapter 15 meant the Amalekites remained to raid Ziklag in chapter 30, creating suffering for God''s anointed; the narrative embeds a causal chain from disobedience to future affliction, a pattern the prophets will systematize as covenant curse', 'The echo is coincidental — Amalekites were simply the most common enemy in the region', 'Saul''s failure to destroy Amalek had no connection to the Ziklag raid since the Amalekites of chapter 30 are a different clan', 'The echo shows God punished David rather than Saul for the incomplete victory in chapter 15', 'a', '1 Samuel 15:9 — "Saul and the people spared Agag, and the best of the sheep." 30:1 — "the Amalekites had invaded the south, and Ziklag, and smitten Ziklag, and burned it." The survival of the Amalekites from chapter 15 directly produces the disaster of chapter 30.'),
('1 Samuel', 30, 'adults', 8, 'How does David''s instruction to the Egyptian "Swear unto me by God, that thou wilt neither kill me, nor deliver me into the hands of my master" (30:15) reflect the pervasive theme of oath and loyalty in 1 Samuel?', 'Oaths by God have governed every major relationship in the book — Jonathan and David''s covenants, David''s oath to spare Saul''s descendants, Saul''s oaths — and here a sick pagan slave demands the same covenant protection from David; the oath principle crosses national and social boundaries, reflecting the Mosaic vision of a covenant order that protects even the alien and the slave', 'The Egyptian''s request for an oath is a self-serving demand for personal safety with no broader significance', 'The oath theme in 1 Samuel is confined to Israelite relationships and the Egyptian slave episode is outside its scope', 'David''s willingness to swear to a foreign slave reflects only practical diplomacy rather than covenant theology', 'a', '1 Samuel 30:15 — "Swear unto me by God, that thou wilt neither kill me, nor deliver me into the hands of my master: and I will bring thee down to this company." The same LORD by whom David and Jonathan swore now guarantees safety for an abandoned Egyptian — covenant protection extends to the most marginal.');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 31, 'teens', 1, 'Where did the battle of Gilboa take place, and what happened to the cities of Israel in that region when the battle was lost?', 'It was at Mount Gilboa; the Israelites that were on the other side of the valley and beyond Jordan fled, the cities were forsaken, and the Philistines came and dwelt in them', 'It was near Jabesh-gilead; the Israelites rallied and held the Jordan crossings even as Saul fell', 'It was at Megiddo; the Philistines were stopped at the mountain pass and held for three days', 'It was on the plains of Jezreel; David''s men secretly held the eastern cities during the battle', 'a', '1 Samuel 31:1,7 — "Now the Philistines fought against Israel: and the men of Israel fled from before the Philistines, and fell down slain in mount Gilboa...And the men of Israel that were on the other side of the valley, and they on the other side Jordan, saw that the men of Israel fled, and that Saul and his sons were dead, they forsook the cities, and fled."'),
('1 Samuel', 31, 'teens', 2, 'What did the Philistines do with Saul''s body and armor after the battle?', 'They cut off his head, put his armor in the house of Ashtaroth, fastened his body to the wall of Beth-shan, and sent messengers to proclaim the news throughout their land', 'They burned his body on the battlefield as was Philistine custom for fallen enemies', 'They preserved his body and displayed it in Gath as a memorial to their victory', 'They kept his armor in the Dagon temple and left his body for the birds of the air', 'a', '1 Samuel 31:9-10 — "And they cut off his head, and stripped off his armour, and sent into the land of the Philistines round about, to publish it in the house of their idols, and among the people. And they put his armour in the house of Ashtaroth: and they fastened his body to the wall of Beth-shan."'),
('1 Samuel', 31, 'teens', 3, 'Why did the men of Jabesh-gilead have a special reason to honor Saul even in death?', 'Saul had saved Jabesh-gilead at the very beginning of his reign when Nahash the Ammonite threatened to gouge out the right eyes of all its people', 'Jabesh-gilead was Saul''s mother''s home city and they were protecting their tribal ancestor', 'Saul had built Jabesh-gilead a new city wall during his reign as an act of generosity', 'Jabesh-gilead''s virgin daughters had been given to the tribe of Benjamin generations before, creating a family bond', 'a', '1 Samuel 11:1-11 — Saul rallied Israel and delivered Jabesh-gilead from Nahash the Ammonite in his first military act as king; 31:11-13 — the men of Jabesh-gilead repay that loyalty by honoring his body decades later.'),
('1 Samuel', 31, 'teens', 4, 'What did the men of Jabesh-gilead do with the bodies after taking them down from the wall?', 'They burned the bodies at Jabesh, took the bones, and buried them under a tree at Jabesh, then fasted seven days', 'They carried the bodies to Ramah for burial near Samuel''s tomb', 'They buried the bodies at the foot of Mount Gilboa where they fell', 'They sent the bones to Gibeah, Saul''s home city, for a royal burial', 'a', '1 Samuel 31:12-13 — "All the valiant men arose, and went all night, and took the body of Saul and the bodies of his sons from the wall of Beth-shan, and came to Jabesh, and burnt them there. And they took their bones, and buried them under a tree at Jabesh, and fasted seven days."'),
('1 Samuel', 31, 'teens', 5, 'How does the death of Jonathan in chapter 31 create a narrative void that 2 Samuel must address?', 'Jonathan and David had made a covenant that David would show kindness to Jonathan''s house forever — Jonathan''s death at Gilboa leaves that covenant unfulfilled until David honors it through Mephibosheth in 2 Samuel 9', 'Jonathan''s death was expected and the narrative treats it as a minor detail since he had already transferred his loyalties to David', 'Jonathan''s death is treated with extensive mourning in chapter 31 making further narrative address unnecessary', 'Jonathan had no surviving children so his death created no ongoing covenant obligations for David', 'a', '1 Samuel 31:2 — "the Philistines slew Jonathan." 1 Samuel 20:42 — "The LORD be between me and thee, and between my seed and thy seed for ever." 2 Samuel 9:1 — "And David said, Is there yet any that is left of the house of Saul, that I may shew him kindness for Jonathan''s sake?"');
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
('1 Samuel', 31, 'adults', 1, 'How does Saul''s death by falling on his own sword function as a final ironic reversal of his entire reign?', 'The king who feared the Philistines'' sword (and thus disobeyed God repeatedly — 13:12, 15:24 — out of fear of military threat) dies by his own sword rather than by a Philistine weapon; the very thing he tried to prevent — ignominious death — arrives through the very instrument he used to rule; his fear became his fate', 'Saul''s self-inflicted death was honorable and the narrative presents it as a noble end', 'The means of Saul''s death carries no symbolic dimension and is simply historical reportage', 'Saul died by his own sword because it was the only weapon available, not because of any ironic significance', 'a', '1 Samuel 31:4 — "Therefore Saul took a sword, and fell upon it." 1 Samuel 13:12 — "the Philistines will come down now upon me to Gilgal, and I have not made supplication unto the LORD: I forced myself therefore, and offered a burnt offering." Fear of the Philistines drove Saul''s first great sin; fear of the Philistines ends his life.'),
('1 Samuel', 31, 'adults', 2, 'The armourbearer''s refusal to kill Saul (31:4) — "for he was sore afraid" — echoes David''s repeated refusals to kill Saul. What does the parallel achieve?', 'The echo highlights the difference in motivation: the armourbearer refused out of fear, not principle; David refused because of theological conviction about the LORD''s anointed; the same external act (not killing Saul) springs from entirely different moral sources — fear versus faith — and the narrative subtly distinguishes the two', 'The parallel shows that the armourbearer shared David''s theology about the anointed', 'The armourbearer''s fear was identical to David''s restraint and the narrative makes no distinction', 'The echo is coincidental since the narrative had no intention of comparing the armourbearer with David', 'a', '1 Samuel 31:4 — "his armourbearer would not; for he was sore afraid." 24:6 — "The LORD forbid that I should do this thing...to stretch forth mine hand against him, seeing he is the anointed of the LORD." One refuses from fear; the other from covenant reverence.'),
('1 Samuel', 31, 'adults', 3, 'The display of Saul''s body on the wall of Beth-shan and his armor in Ashtaroth''s temple (31:10) echoes what earlier episode in the book and what does the echo teach?', 'Goliath''s armor was placed in the sanctuary at Nob after David''s victory (1 Sam. 21:9) as a trophy of divine favor — now Saul''s armor is placed in Ashtaroth''s temple as a trophy of Philistine gods; the two armor deposits frame the David-Saul conflict: divine victory displayed in a sanctuary versus human defeat displayed in an idol''s house', 'The armor display has no connection to the earlier Nob episode and serves only as historical detail', 'The echo is thematic but unintentional since different authors wrote the two passages', 'Saul''s armor in Ashtaroth''s temple proves Saul had secretly worshipped Ashtaroth during his reign', 'a', '1 Samuel 21:9 — "the sword of Goliath the Philistine...wrapped in a cloth behind the ephod." 31:10 — "they put his armour in the house of Ashtaroth." Armor in the sanctuary marks divine victory; armor in the idol''s house marks divine abandonment.'),
('1 Samuel', 31, 'adults', 4, 'What is the canonical significance of Jabesh-gilead''s loyalty to Saul''s corpse in light of Judges 21 and the connection between Benjamin and Jabesh-gilead established there?', 'The four hundred virgins of Jabesh-gilead given to the Benjamites in Judges 21 created a marriage bond between the two communities; Saul, a Benjamite, is the fruit of that genealogical connection; Jabesh-gilead''s night rescue of Saul''s body is the canon''s longest-range act of familial loyalty, spanning from the Judges period to the monarchic era', 'Jabesh-gilead''s loyalty was motivated purely by Saul''s rescue of them in 1 Samuel 11 with no Judges connection', 'The Judges 21 bond was dissolved by the time of Saul and has no relevance to chapter 31', 'Jabesh-gilead was a Benjamite city itself and the loyalty was tribal rather than marital', 'a', 'Judges 21:12,14 — four hundred virgins of Jabesh-gilead given to Benjamin. 1 Samuel 9:1-2 — Saul is a Benjamite. 31:11-13 — Jabesh-gilead honors Saul''s body. The genealogical thread runs from Judges 21 to 1 Samuel 31 across the entire pre-monarchic period.'),
('1 Samuel', 31, 'adults', 5, 'How does the burning of Saul''s body at Jabesh (31:12) relate to Israelite burial customs, and why might the men of Jabesh-gilead have done this?', 'Cremation was rare in Israel (typically reserved for the executed or shamed — Josh. 7:25), but the context suggests practical necessity: the bodies were already in severe post-battle condition after being displayed on the Beth-shan wall; the burning may have been a purificatory act followed by honorable bone burial rather than dishonoring cremation, as evidenced by the subsequent interment of the bones', 'Cremation was standard Israelite burial practice at this period and carries no unusual significance', 'The burning was a Philistine custom that Jabesh-gilead adopted to prevent the Philistines from reclaiming the bodies', 'The cremation was a sign of disrespect for Saul''s memory and the narrative records it as a failure of loyalty', 'a', '1 Samuel 31:12-13 — "burnt them there. And they took their bones, and buried them under a tree at Jabesh." The bones are carefully buried after the burning — the combination of burning and burial suggests protective purification rather than rejection.'),
('1 Samuel', 31, 'adults', 6, 'How does 1 Samuel 31 parallel 1 Samuel 4 — the death of Eli''s sons and the capture of the ark — in terms of the book''s opening and closing movements?', 'Both chapters record the catastrophic death of a priestly/royal family (Hophni and Phinehas in ch. 4; Jonathan and Saul''s sons in ch. 31), the flight and abandonment of Israelite cities, and the desecration of holy things by Philistines (the ark in ch. 4; Saul''s armor in ch. 31); the book opens and closes with Philistine triumph over corrupt Israelite leadership, framing the entire narrative as a search for faithful leadership', 'Chapters 4 and 31 are thematically unrelated — one concerns priestly leadership and the other royal leadership', 'The parallel is superficial since the theological outcomes of chapters 4 and 31 are entirely different', 'The book closes with Israelite triumph rather than defeat and chapter 31 should be read as transitional rather than parallel to chapter 4', 'a', '1 Samuel 4:11 — "the two sons of Eli, Hophni and Phinehas, were slain." 31:2 — "the Philistines slew Jonathan, and Abinadab, and Malchishua." Both dynasties — priestly and royal — end with sons killed by Philistines; the structural parallel closes the book''s first movement.'),
('1 Samuel', 31, 'adults', 7, 'The phrase "when the men of Israel that were on the other side of the valley...saw that the men of Israel fled, and that Saul and his sons were dead, they forsook the cities, and fled" (31:7) represents what theological verdict on Saul''s kingship?', 'The collapse of an entire region''s population when one man falls is the narrative''s indictment of kingship built on personality rather than covenant — Saul was never able to ground Israel''s security in God and thus his personal death produced national abandonment; the very thing Israel feared if they had no king (1 Sam. 8:20 — "fight our battles") now occurs because of the king they chose', 'The flight of the Israelites was a rational military response with no theological dimension', 'The verse demonstrates that Saul had been a successful king who was simply overwhelmed by superior Philistine forces', 'The population''s flight was temporary and they returned quickly once David was anointed, negating any theological verdict', 'a', '1 Samuel 8:20 — "that our king may judge us, and go out before us, and fight our battles." 31:7 — "they forsook the cities, and fled." The king Israel demanded to fight their battles is dead, and his death produces the very nationlessness they had feared without a king — but the wrong kind of king makes it worse.'),
('1 Samuel', 31, 'adults', 8, 'How does the ending of 1 Samuel — with Saul''s death, burial, and the implied rise of David — function typologically as a pattern for the death of the old covenant and the inauguration of the new in New Testament theology?', 'Saul''s reign — inaugurated with popular acclaim, operating by self-will rather than divine command, ending in defeat and death — types the old covenant''s Sinai administration that Paul describes as a "ministration of condemnation" (2 Cor. 3:9); David, the anointed one who suffers before reigning, types the new covenant''s Davidic administration; the close of 1 Samuel is the close of one dispensation and the opening of another', 'The ending of 1 Samuel has no typological significance for New Testament theology', 'Saul types only the individual unbeliever rather than a covenantal administration', 'The transition from Saul to David types only the historical development of the Israelite monarchy with no redemptive-historical dimensions', 'a', '1 Samuel 31:4 — Saul falls on his sword. 2 Samuel 2:4 — David is anointed. Hebrews 8:13 — "In that he saith, A new covenant, he hath made the first old. Now that which decayeth and waxeth old is ready to vanish away." The Saul-David transition embeds the old-to-new covenant pattern that the entire canon will unfold.');
